return ['domain'=>'agnosis','plural-forms'=>'nplurals=2; plural=n != 1;','language'=>'ur','project-id-version'=>'Agnosis 0.9.21','pot-creation-date'=>'2026-07-16T07:59+00:00','po-revision-date'=>'2026-07-12 18:25+0000','x-generator'=>'Loco https://localise.biz/','messages'=>['Agnosis'=>'Agnosis','https://agnosis.art'=>'https://agnosis.art','Art blooming out of oblivion. Email your art, AI polishes it, the world sees it. A free, federated publishing network for independent artists.'=>'فراموشی سے ابھرتا ہوا فن۔ اپنی آرٹ ای میل کریں، اے آئی اسے نکھار دیتی ہے، دنیا اسے دیکھتی ہے۔ آزاد فنکاروں کے لیے ایک مفت، فیڈریٹڈ اشاعتی نیٹ ورک۔','Agnosis requires PHP %s or higher.'=>'Agnosis کو PHP %s یا اس سے اعلیٰ درکار ہے۔','Agnosis requires WordPress %s or higher.'=>'Agnosis کو WordPress %s یا اس سے اعلیٰ درکار ہے۔','Filter by medium'=>'میڈیم کے لحاظ سے فلٹر کریں','All'=>'سب','Enlarged image'=>'بڑا کیا گیا تصویر','Featured'=>'نمایاں','Enlarge'=>'بڑا کریں','Gallery pages'=>'گیلری صفحات','Prev'=>'پچھلا','Next'=>'اگلا','Contact Messages'=>'رابطہ پیغامات','No contact messages yet.'=>'ابھی تک کوئی رابطہ پیغامات نہیں۔','No messages match this filter.'=>'اس فلٹر سے کوئی پیغامات نہیں ملتے۔','#'=>'#','Artist'=>'فنکار','From'=>'منجانب','Message'=>'پیغام','Status'=>'حالت','Received'=>'موصول ہوا','Actions'=>'کارروائیاں','(deleted artist #%d)'=>'(حذف شدہ فنکار #%d)','You do not have permission to perform this action.'=>'آپ کے پاس یہ کارروائی کرنے کی اجازت نہیں ہے۔','Message deleted.'=>'پیغام حذف کر دیا گیا۔','All statuses'=>'تمام حالتیں','Sent'=>'بھیجا گیا','Rejected'=>'مسترد','Filter'=>'فلٹر','Reset'=>'دوبارہ سیٹ کریں','Page %1$d of %2$d'=>'صفحہ %1$d از %2$d','Previous'=>'پچھلا','Delete this message?'=>'کیا یہ پیغام حذف کرنا ہے؟','Delete'=>'حذف کریں','just now'=>'ابھی ابھی','%dm ago'=>'%d منٹ پہلے','%dh ago'=>'%d گھنٹے پہلے','Mail from (workflow)'=>'Mail from (workflow)','Newsletter'=>'نیوز لیٹر','Agnosis Inbox'=>'Agnosis اِن باکس','Inbox'=>'اِن باکس','No messages in the queue yet. Click "Poll Inbox" to fetch messages from your IMAP account.'=>'قطار میں ابھی تک کوئی پیغام نہیں۔ اپنے IMAP اکاؤنٹ سے پیغامات حاصل کرنے کے لیے "Poll Inbox" پر کلک کریں۔','No queue rows match this filter.'=>'اس فلٹر سے قطار کی کوئی قطاریں نہیں ملتیں۔','Subject'=>'موضوع','Endpoint'=>'اینڈپوائنٹ','Files'=>'فائلیں','Error'=>'غلطی','unregistered sender'=>'غیر رجسٹرڈ بھیجنے والا','Old row — delete and re-poll to preview'=>'پرانی قطار — پیش نظارہ کے لیے حذف کریں اور دوبارہ پول کریں','Attachment viewer'=>'منسلکہ دیکھنے والا','Close'=>'بند کریں','Queue row deleted. Poll Inbox to re-fetch the message.'=>'قطار کی قطار حذف ہو گئی۔ پیغام دوبارہ حاصل کرنے کے لیے ان باکس کو پول کریں۔','Queue #%d sent to pipeline. Check back in a few seconds.'=>'قطار #%d پائپ لائن کو بھیج دی گئی۔ چند سیکنڈ بعد دوبارہ چیک کریں۔','Poll complete. %d new message(s) added to the queue.'=>'پول مکمل۔ قطار میں %d نئے پیغام شامل کر دیے گئے۔','Force-reprocess: %1$d row(s) reset, %2$d new message(s) enqueued.'=>'فورس ری پروسیس: %1$d قطار(یں) ری سیٹ ہو گئیں، %2$d نئے پیغام قطار میں شامل ہو گئے۔','Processed %d pending item(s).'=>'%d زیرِ التوا آئٹم(ز) پر کارروائی ہو گئی۔','Pending'=>'زیرِ التوا','Processing'=>'زیرِ کارروائی','Published'=>'شائع شدہ','Failed'=>'ناکام','Skipped'=>'چھوڑ دیا گیا','All reasons'=>'تمام وجوہات','%1$d message from an unregistered sender is hidden from this view. <a href="%2$s">View it</a>.'=>'%1$d غیر رجسٹرڈ بھیجنے والے کا پیغام اس منظر سے چھپا ہوا ہے۔ <a href="%2$s">اسے دیکھیں</a>۔' . "\0" . '%1$d غیر رجسٹرڈ بھیجنے والوں کے پیغامات اس منظر سے چھپے ہوئے ہیں۔ <a href="%2$s">انہیں دیکھیں</a>۔','Poll Inbox'=>'ان باکس کو پول کریں','Force Reprocess'=>'فورس ری پروسیس','Process All Pending'=>'تمام زیرِ التوا پر کارروائی کریں','Goodbye'=>'الوداع','Community'=>'کمیونٹی','Bounce'=>'باؤنس','Awaiting Review'=>'جائزے کا منتظر','Live'=>'فعال','Processed'=>'کارروائی شدہ','Member Removed'=>'رکن ہٹا دیا گیا','Broadcast Sent'=>'براڈکاسٹ بھیج دی گئی','Bounced (too long)'=>'باؤنس ہو گیا (بہت لمبا)','Handled'=>'ہینڈل کیا گیا','Process'=>'کارروائی کریں','View Post'=>'پوسٹ دیکھیں','Reprocess'=>'دوبارہ کارروائی کریں','Running…'=>'چل رہا ہے…','Delete this queue row?'=>'کیا یہ قطار کی قطار حذف کر دی جائے؟','Configuration'=>'تشکیل','Force-reprocess complete. %1$d queue row(s) reset, %2$d new message(s) enqueued. Click "Process Pending Queue" to run the AI pipeline.'=>'فورس ری پروسیس مکمل۔ %1$d قطار(یں) ری سیٹ ہو گئیں، %2$d نئے پیغام قطار میں شامل ہو گئے۔ AI پائپ لائن چلانے کے لیے "Process Pending Queue" پر کلک کریں۔','Log cleared.'=>'لاگ صاف کر دیا گیا۔','Debug files cleared. %d file was removed.'=>'ڈیبگ فائلیں صاف کر دی گئیں۔ %d فائل حذف کی گئی۔' . "\0" . 'ڈیبگ فائلیں صاف کر دی گئیں۔ %d فائلیں حذف کی گئیں۔','Term translation cache cleared. Terms will be re-translated the next time they\'re needed.'=>'ترجمہ کیش صاف کر دی گئی۔ اصطلاحات کی اگلی ضرورت پر دوبارہ ترجمہ کیا جائے گا۔','Processed %d pending queue item(s). Check the Logs tab for details.'=>'%d زیرِ التوا قطار آئٹم(ز) پر کارروائی ہو گئی۔ تفصیل کے لیے لاگز ٹیب دیکھیں۔','Poll complete. %d new message(s) enqueued. Check the Logs tab, then click Process Pending Queue.'=>'پول مکمل۔ %d نئے پیغام قطار میں شامل ہو گئے۔ تفصیل کے لیے لاگز ٹیب دیکھیں، پھر Process Pending Queue پر کلک کریں۔','Applicant admitted. A welcome email has been sent.'=>'درخواست گزار کو داخل کر لیا گیا۔ خوش آمدیدی ای میل بھیج دی گئی ہے۔','Could not admit — the application may no longer be pending.'=>'داخل نہیں کیا جا سکا — ممکن ہے درخواست اب زیرِ التوا نہ ہو۔','Application rejected.'=>'درخواست مسترد کر دی گئی۔','Could not reject — the application may no longer be pending.'=>'مسترد نہیں کیا جا سکا — ممکن ہے درخواست اب زیرِ التوا نہ ہو۔','Artist suspended. A notification email has been sent.'=>'فنکار معطل کر دیا گیا۔ اطلاع کی ای میل بھیج دی گئی ہے۔','Could not suspend the artist — they may no longer be active.'=>'فنکار کو معطل نہیں کیا جا سکا — ممکن ہے وہ اب فعال نہ ہو۔','Artist permanently deleted. Their account and all content have been removed.'=>'فنکار کو مستقل طور پر حذف کر دیا گیا۔ ان کا اکاؤنٹ اور تمام مواد ہٹا دیا گیا ہے۔','Could not delete the artist — please try again.'=>'فنکار کو حذف نہیں کیا جا سکا — براہِ کرم دوبارہ کوشش کریں۔','Community removal vote opened. All artists have been emailed.'=>'کمیونٹی کے حذف کرنے کے ووٹ کا آغاز ہو گیا۔ تمام فنکاروں کو ای میل کر دی گئی ہے۔','Could not open a removal vote — one may already be active for this artist.'=>'حذف کرنے کا ووٹ نہیں کھولا جا سکا — ممکن ہے اس فنکار کے لیے پہلے ہی ایک فعال ہو۔','Issue prepared and queued — it will go out over the next few cron cycles.'=>'شماره تیار ہو کر قطار میں لگا دیا گیا ہے — یہ اگلے چند کرون سائیکلز میں بھیج دیا جائے گا۔','Could not start this issue — a previous one may still be sending.'=>'یہ شمارہ شروع نہیں ہو سکا — ممکن ہے پچھلا شمارہ اب بھی بھیجا جا رہا ہو۔','Test email sent — check the inbox you sent it to.'=>'ٹیسٹ ای میل بھیج دی گئی ہے — جس ان باکس پر آپ نے بھیجی تھی، اسے چیک کریں۔','Could not send the test email — check the address and your site\'s outgoing mail configuration.'=>'ٹیسٹ ای میل نہیں بھیجی جا سکی — ایڈریس اور آپ کی سائٹ کی آؤٹ گوئنگ میل کنفیگریشن چیک کریں۔','Invitation sent.'=>'دعوت نامہ بھیج دیا گیا ہے۔','Could not send the invitation — check the address and your site\'s outgoing mail configuration.'=>'دعوت نامہ نہیں بھیجا جا سکا — ایڈریس اور آپ کی سائٹ کی آؤٹ گوئنگ میل کنفیگریشن چیک کریں۔','Test invitation sent — check the inbox you sent it to.'=>'ٹیسٹ دعوت نامہ بھیج دیا گیا ہے — جس ان باکس پر آپ نے بھیجا تھا، اسے چیک کریں۔','Could not send the test invitation — check the address and your site\'s outgoing mail configuration.'=>'ٹیسٹ دعوت نامہ نہیں بھیجا جا سکا — ایڈریس اور آپ کی سائٹ کی آؤٹ گوئنگ میل کنفیگریشن چیک کریں۔','Test email sent — check whether it lands in your inbox or your spam folder.'=>'ٹیسٹ ای میل بھیج دی گئی ہے — دیکھیں کہ یہ آپ کے ان باکس میں جاتی ہے یا اسپام فولڈر میں۔','Failed recipients reset to pending — they will be retried on the next few cron cycles.'=>'ناکام وصول کنندگان کو دوبارہ زیرِ التوا پر سیٹ کر دیا گیا ہے — اگلے چند کرون سائیکلز میں دوبارہ کوشش کی جائے گی۔','No failed recipients to retry for this newsletter.'=>'اس نیوز لیٹر کے لیے دوبارہ کوشش کرنے کے لیے کوئی ناکام وصول کنندہ موجود نہیں۔','Art blooming out of oblivion'=>'فراموشی سے پھوٹتی ہوئی تخلیق','Save Changes'=>'تبدیلیاں محفوظ کریں','Members'=>'اراکین','Rules'=>'قواعد','General'=>'عام','Email Inbox'=>'ای میل ان باکس','AI Providers'=>'اے آئی فراہم کنندگان','Behavior'=>'رویہ','Network'=>'نیٹ ورک','Commerce'=>'تجارت','Logs'=>'لاگز','— None (inline message only) —'=>'— کوئی نہیں (صرف اِن لائن پیغام) —','Reset to default'=>'طے شدہ پر دوبارہ سیٹ کریں','Replaces the text above with the plugin\'s built-in default — click Save Changes below to keep it.'=>'اوپر کے متن کو پلگ اِن کے اندرونی طے شدہ متن سے بدل دیتا ہے — اسے برقرار رکھنے کے لیے نیچے "تبدیلیاں محفوظ کریں" پر کلک کریں۔','Select Image'=>'تصویر منتخب کریں','Remove'=>'ہٹائیں','Base domain'=>'بنیادی ڈومین','Root domain for artist subdomains, e.g. agnosis.art. Each artist is reachable at nicename.{base_domain}. Requires a wildcard DNS record (*.{base_domain}) pointing to this server. Leave blank to disable subdomain routing.'=>'آرٹسٹ سب ڈومینز کے لیے روٹ ڈومین، مثلاً agnosis.art۔ ہر آرٹسٹ nicename.{base_domain} پر دستیاب ہوگا۔ اس کے لیے ایک وائلڈ کارڈ DNS ریکارڈ (*.{base_domain}) درکار ہے جو اس سرور کی طرف اشارہ کرے۔ سب ڈومین روٹنگ غیر فعال کرنے کے لیے خالی چھوڑ دیں۔','Debug logging'=>'ڈیبگ لاگنگ','Writes raw diagnostic dumps of the email intake pipeline (message structure, attachment MIME detection, media conversion, post creation) to a dedicated debug directory — far more detail than the Logs tab keeps, for tracing exactly where a submission was rejected or lost. Turn off once you have what you need; files can accumulate quickly. Can also be forced from wp-config.php with `define( \'AGNOSIS_DEBUG\', true );`, which overrides this toggle. See the Debug Files panel below for the directory location and a clear-files button.'=>'ای میل انٹیک پائپ لائن کے خام تشخیصی ڈمپ لکھتا ہے (پیغام کی ساخت، اٹیچمنٹ MIME شناخت، میڈیا کنورژن، پوسٹ تخلیق) ایک مخصوص ڈیبگ ڈائریکٹری میں — لاگز ٹیب کے مقابلے میں کہیں زیادہ تفصیل، تاکہ یہ معلوم کیا جا سکے کہ جمع کرائی گئی چیز کہاں رد ہوئی یا گم ہوئی۔ جب ضرورت پوری ہو جائے تو بند کر دیں؛ فائلیں تیزی سے جمع ہو سکتی ہیں۔ اسے wp-config.php سے `define( \'AGNOSIS_DEBUG\', true );` کے ذریعے بھی زبردستی فعال کیا جا سکتا ہے، جو اس ٹوگل کو اووررائیڈ کر دے گا۔ ڈائریکٹری کا مقام اور فائلیں صاف کرنے کا بٹن نیچے Debug Files پینل میں دیکھیں۔','Debug file retention (days)'=>'ڈیبگ فائل برقرار رکھنے کی مدت (دن)','Debug dumps older than this are permanently deleted by the daily cleanup — automatically, whether or not debug logging is currently turned on, so files left over from a past debug session don\'t linger indefinitely. A dump is a full raw copy of an artist\'s email, so this defaults shorter than the inbox/queue retention above. Default: 14 days.'=>'اس مدت سے پرانی ڈیبگ ڈمپ فائلیں روزانہ کی صفائی کے ذریعے مستقل طور پر حذف کر دی جاتی ہیں — خودکار طور پر، چاہے ڈیبگ لاگنگ اس وقت آن ہو یا نہ ہو، تاکہ پچھلے ڈیبگ سیشن کی بچی ہوئی فائلیں غیرمعینہ مدت تک موجود نہ رہیں۔ ایک ڈمپ، آرٹسٹ کی ای میل کی مکمل خام نقل ہوتی ہے، اس لیے اس کی ڈیفالٹ مدت اوپر والے ان باکس/قطار برقرار رکھنے سے کم رکھی گئی ہے۔ ڈیفالٹ: 14 دن۔','Preset biography title'=>'پیشگی مقررہ سوانحی عنوان','When set, every artist\'s biography page uses this exact title instead of their own, regardless of what the artist submitted, edited on their approve form, or later changed on their published page. Leave blank to keep using each artist\'s own title (the default). Shown exactly as typed here on every language version of a biography page — not machine-translated per language. See "Include artist\'s name in preset title" below.'=>'جب یہ سیٹ ہو، ہر آرٹسٹ کے سوانحی صفحے پر ان کے اپنے عنوان کی بجائے یہی عین عنوان استعمال ہوگا، قطع نظر اس کے کہ آرٹسٹ نے کیا جمع کرایا، اپنی منظور شدہ فارم میں کیا ایڈٹ کیا، یا بعد میں اپنے شائع شدہ صفحے پر کیا بدلا۔ ہر زبان کے ورژن میں سوانحی صفحے پر یہی عنوان لفظ بہ لفظ دکھایا جائے گا — زبان کے لحاظ سے مشینی ترجمہ نہیں کیا جائے گا۔ نیچے "پیشگی مقررہ عنوان میں آرٹسٹ کا نام شامل کریں" دیکھیں۔','Include artist\'s name in preset title'=>'پیشگی مقررہ عنوان میں آرٹسٹ کا نام شامل کریں','When the preset title above is set, append the artist\'s own WordPress display name to it (e.g. "Meet the Artist — Jane Doe"). Has no effect while the preset title is blank.'=>'جب اوپر والا پیشگی مقررہ عنوان سیٹ ہو، تو اس کے ساتھ آرٹسٹ کا اپنا ورڈپریس ڈسپلے نام شامل کر دیں (مثلاً "آرٹسٹ سے ملو — جین ڈو")۔ جب پیشگی مقررہ عنوان خالی ہو تو اس کا کوئی اثر نہیں ہوگا۔','Cloudflare Turnstile site key'=>'کلاؤڈ فلیئر ٹرن اسٹائل سائٹ کلید','From your Cloudflare Turnstile widget (dash.cloudflare.com → Turnstile). Adds a human-verification check to the public Subscribe (newsletter-signup) and Join forms. Leave either key blank to leave both forms exactly as they are today.'=>'آپ کے Cloudflare Turnstile ویجیٹ (dash.cloudflare.com → Turnstile) سے۔ عوامی سبسکرائب (نیوز لیٹر سائن اپ) اور جوائن فارموں میں انسانی تصدیق کا چیک شامل کرتی ہے۔ دونوں فارموں کو ان کی موجودہ حالت میں رکھنے کے لیے کوئی بھی کلید خالی چھوڑ دیں۔','Cloudflare Turnstile secret key'=>'کلاؤڈ فلیئر ٹرن اسٹائل خفیہ کلید','Kept server-side only — used to verify each form submission directly with Cloudflare before it is accepted.'=>'صرف سرور پر محفوظ — ہر فارم سبمیشن کو قبول کرنے سے پہلے Cloudflare کے ساتھ براہِ راست اس کی تصدیق کے لیے استعمال ہوتی ہے۔','Email logo'=>'ای میل لوگو','Email driver'=>'ای میل ڈرائیور','Artwork submissions address'=>'آرٹ ورک جمع کرانے کا پتہ','Artists send artwork to this address — e.g. submit@agnosis.art'=>'آرٹسٹ اپنا آرٹ ورک اس پتے پر بھیجتے ہیں — مثلاً submit@agnosis.art','Biography submissions address'=>'سوانحی جمع کرانے کا پتہ','Artists send biography updates to this address — e.g. bio@agnosis.art'=>'آرٹسٹ اپنی سوانحی معلومات کی تازہ کاری اس پتے پر بھیجتے ہیں — مثلاً bio@agnosis.art','Event submissions address'=>'ایونٹ جمع کرانے کا پتہ','Artists send event announcements to this address — e.g. event@agnosis.art'=>'آرٹسٹ ایونٹ کے اعلانات اس پتے پر بھیجتے ہیں — مثلاً event@agnosis.art','Replace artwork address'=>'آرٹ ورک کا پتہ بدلیں','Artist sends a new version of an existing artwork. Subject must match the original title. Bypasses duplicate detection — e.g. replace@agnosis.art'=>'فنکار موجودہ آرٹ ورک کا نیا ورژن بھیجتا ہے۔ موضوع اصل عنوان سے بالکل ملنا چاہیے۔ ڈپلیکیٹ شناخت کو بائی پاس کرتا ہے — مثلاً replace@agnosis.art','Removal request address'=>'ہٹانے کی درخواست کا پتہ','Artist requests takedown of an existing artwork. Subject must match the title. Moves the post to draft pending admin review — e.g. remove@agnosis.art'=>'فنکار موجودہ آرٹ ورک کو ہٹانے کی درخواست کرتا ہے۔ موضوع عنوان سے بالکل ملنا چاہیے۔ پوسٹ کو ڈرافٹ میں منتقل کر دیتا ہے، ایڈمن کے جائزے کے زیرِ التوا — مثلاً remove@agnosis.art','Promote artwork address'=>'آرٹ ورک کو نمایاں کرنے کا پتہ','Artist sends an email here (subject = exact artwork title) to choose which artwork represents them in the shared community gallery on the main site — not their own subdomain, which already shows everything they\'ve published. Any previously featured artwork is automatically demoted — e.g. promote@agnosis.art'=>'فنکار یہاں ای میل بھیجتا ہے (موضوع = آرٹ ورک کا بالکل درست عنوان) تاکہ یہ چُن سکے کہ مشترکہ کمیونٹی گیلری میں مین سائٹ پر کون سا آرٹ ورک اس کی نمائندگی کرے — نہ کہ اس کا اپنا سب ڈومین، جو پہلے ہی اس کی شائع کردہ ہر چیز دکھاتا ہے۔ کوئی بھی پہلے سے نمایاں آرٹ ورک خود بخود غیر نمایاں ہو جاتا ہے — مثلاً promote@agnosis.art','Photo-only address'=>'صرف تصویر والا پتہ','Opt-out lane for photographers and lens-based artists whose photograph is the artwork, not a snapshot of it. Submissions here are published with the original image exactly as sent — AI enhancement is skipped and the quality-rejection gate is bypassed. AI description (title, tags, alt text) still runs. Use the [Photo] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. photo@agnosis.art'=>'فوٹوگرافرز اور لینس پر مبنی فنکاروں کے لیے آپٹ آؤٹ راستہ، جن کے لیے خود تصویر ہی آرٹ ورک ہے، اس کی محض اسنیپ شاٹ نہیں۔ یہاں جمع کرائی گئی چیزیں اصل تصویر کے ساتھ بالکل ویسی ہی شائع ہوتی ہیں جیسی بھیجی گئی ہوں — AI بہتری چھوڑ دی جاتی ہے اور معیار-ردی دروازہ بائی پاس ہو جاتا ہے۔ AI وضاحت (عنوان، ٹیگز، alt text) پھر بھی چلتی ہے۔ ایسے میل کلائنٹس کے لیے جو To: aliases سپورٹ نہیں کرتے، بطور متبادل [Photo] موضوع اشارہ استعمال کریں — مثلاً photo@agnosis.art','Pure address (no AI at all)'=>'خالص پتہ (بالکل کوئی AI نہیں)','Strictest opt-out lane: nothing sent here is touched by AI — no enhancement, no vision description, no rewriting. The published post title, body, and translated-title subtitle are taken verbatim from the artist\'s own subject and message text; the attached file(s) are published exactly as sent. The quality-rejection gate is bypassed, same as Photo-only. Use the [Pure] subject indicator as a fallback for mail clients that do not support To: aliases — e.g. pure@agnosis.art'=>'سب سے سخت آپٹ آؤٹ راستہ: یہاں بھیجی گئی کسی بھی چیز کو AI نہیں چھوتا — نہ بہتری، نہ بصری وضاحت، نہ دوبارہ لکھنا۔ شائع شدہ پوسٹ کا عنوان، متن، اور ترجمہ شدہ عنوان والا ذیلی عنوان فنکار کے اپنے موضوع اور پیغام کے متن سے جوں کا توں لیا جاتا ہے؛ منسلک فائلیں بھی بالکل ویسی ہی شائع ہوتی ہیں جیسی بھیجی گئی ہوں۔ معیار-ردی دروازہ بائی پاس ہو جاتا ہے، بالکل Photo-only کی طرح۔ ایسے میل کلائنٹس کے لیے جو To: aliases سپورٹ نہیں کرتے، بطور متبادل [Pure] موضوع اشارہ استعمال کریں — مثلاً pure@agnosis.art','Goodbye / self-removal address'=>'الوداع / خود ہٹانے کا پتہ','Artist emails here (any subject, no attachment needed) to request account deletion. A confirmation link is emailed back before anything is deleted — e.g. goodbye@agnosis.art'=>'فنکار یہاں ای میل کرتا ہے (کوئی بھی موضوع، اٹیچمنٹ درکار نہیں) تاکہ اکاؤنٹ حذف کرنے کی درخواست کرے۔ کچھ بھی حذف کرنے سے پہلے تصدیقی لنک ای میل کیا جاتا ہے — مثلاً goodbye@agnosis.art','Community announcement address'=>'کمیونٹی اعلان کا پتہ','Any active artist emails here (any subject, no attachment needed) to send a message to every other community member — e.g. community@agnosis.art. Never processed as a submission and never becomes a post: each recipient gets the subject and message translated into their own language, with the sender\'s name and email included so they can reply directly. Sent from the address configured under Settings → Community → Rules, which can be different from this one. Only works for a message sent by an active, admitted artist.'=>'کوئی بھی فعال فنکار یہاں ای میل کرتا ہے (کوئی بھی موضوع، اٹیچمنٹ درکار نہیں) تاکہ کمیونٹی کے ہر دوسرے رکن کو پیغام بھیجے — مثلاً community@agnosis.art۔ اسے کبھی بھی submission کے طور پر process نہیں کیا جاتا اور یہ کبھی post نہیں بنتا: ہر وصول کنندہ کو موضوع اور پیغام اس کی اپنی زبان میں ترجمہ کر کے ملتا ہے، اور بھیجنے والے کا نام اور ای میل شامل ہوتی ہے تاکہ وہ براہِ راست جواب دے سکے۔ یہ اس پتے سے بھیجا جاتا ہے جو Settings → Community → Rules کے تحت configure ہوتا ہے، جو اس پتے سے مختلف ہو سکتا ہے۔ صرف اسی پیغام کے لیے کام کرتا ہے جو کسی فعال، منظور شدہ فنکار نے بھیجا ہو۔','IMAP host'=>'IMAP میزبان','e.g. imap.yourhost.com'=>'مثلاً imap.yourhost.com','IMAP port'=>'IMAP پورٹ','Use SSL'=>'SSL استعمال کریں','Skip SSL certificate validation'=>'SSL سرٹیفکیٹ کی تصدیق چھوڑ دیں','⚠ Use only as a temporary workaround when your mail server\'s certificate is not yet trusted (e.g. Plesk self-signed cert before Let\'s Encrypt is applied to the mail daemon). Disable this once the mail server presents a valid certificate.'=>'⚠ صرف عارضی حل کے طور پر استعمال کریں جب آپ کے میل سرور کا سرٹیفکیٹ ابھی قابلِ اعتماد نہ ہو (مثلاً Plesk کا self-signed سرٹیفکیٹ جب تک Let\'s Encrypt میل daemon پر لاگو نہ ہو جائے)۔ جب میل سرور درست سرٹیفکیٹ پیش کرنے لگے تو اسے بند کر دیں۔','IMAP username'=>'IMAP صارف نام','Login username for the IMAP account — typically the catch-all mailbox address.'=>'IMAP اکاؤنٹ کے لیے لاگ اِن صارف نام — عموماً catch-all mailbox کا پتہ۔','Submission email password'=>'سبمیشن ای میل پاس ورڈ','Webhook secret'=>'Webhook راز','HMAC secret shared with your webhook provider (Mailgun, SendGrid…). Used for both the inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) and the bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) — point your provider\'s bounce/spam-complaint webhook at the latter to keep your subscriber and artist addresses clean.'=>'آپ کے webhook فراہم کنندہ (Mailgun، SendGrid…) کے ساتھ مشترک HMAC راز۔ inbound-mail endpoint (/wp-json/agnosis/v1/email/inbound) اور bounce/complaint events endpoint (/wp-json/agnosis/v1/email/events) دونوں کے لیے استعمال ہوتا ہے — اپنے فراہم کنندہ کا bounce/spam-complaint webhook آخری والے پر point کریں تاکہ آپ کے subscriber اور artist پتے صاف رہیں۔','Inbox retention (days)'=>'ان باکس تحفظ (دن)','IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.'=>'IMAP messages and processed/failed queue rows older than this are permanently deleted by the daily cleanup, whether read or unread. Default: 7 days.','Contact message retention (days)'=>'رابطہ پیغام تحفظ (دن)','Visitor-to-artist contact messages (sent or rejected) older than this are permanently deleted by the daily cleanup. The visitor\'s IP address is cleared independently after 30 days regardless of this setting, once it\'s no longer useful for abuse investigation. Default: 90 days.'=>'وزیٹر سے فنکار تک رابطہ پیغامات (بھیجے گئے یا مسترد) جو اس سے پرانے ہوں، روزانہ صفائی کے ذریعے مستقل طور پر حذف کر دیے جاتے ہیں۔ وزیٹر کا IP پتہ 30 دن بعد، اس ترتیب سے قطع نظر، الگ سے صاف کر دیا جاتا ہے، جب وہ اب بدسلوکی کی تحقیق کے لیے مفید نہ رہے۔ طے شدہ: 90 دن۔','Per-sender hourly submission limit'=>'فی بھیجنے والے فی گھنٹہ سبمیشن حد','Maximum submissions accepted from a single artist per hour, across both IMAP and webhook intake. Exceeding this limit silently drops the message (no retry from ESPs). Default: 5.'=>'ایک ہی فنکار سے فی گھنٹہ قبول کی جانے والی زیادہ سے زیادہ submissions، IMAP اور webhook intake دونوں میں۔ اس حد سے تجاوز کرنے پر پیغام خاموشی سے رد ہو جاتا ہے (ESPs کی طرف سے کوئی retry نہیں)۔ طے شدہ: 5۔','Per-artist contact limit'=>'فی فنکار رابطہ حد','Maximum messages the same visitor (by email address) can send to a single artist within the window below — applies across every language version of that artist\'s page. Default: 2.'=>'ایک ہی وزیٹر (ای میل پتے کے ذریعے) کی طرف سے ایک ہی فنکار کو نیچے دی گئی مدت کے اندر بھیجے جانے والے زیادہ سے زیادہ پیغامات — اس فنکار کے صفحے کے ہر زبان والے ورژن پر لاگو ہوتا ہے۔ طے شدہ: 2۔','Per-artist contact limit window (hours)'=>'فی فنکار رابطہ حد کی مدت (گھنٹے)','Time window, in hours, the per-artist contact limit above applies over. Also controls how long a visitor sees the "already contacted" notice instead of the form after messaging an artist. Default: 1 (one hour).'=>'گھنٹوں میں وہ مدت جس پر اوپر دی گئی فی فنکار رابطہ حد لاگو ہوتی ہے۔ یہ بھی کنٹرول کرتی ہے کہ کسی فنکار کو پیغام بھیجنے کے بعد وزیٹر کب تک فارم کی بجائے "already contacted" اطلاع دیکھتا ہے۔ طے شدہ: 1 (ایک گھنٹہ)۔','Require SPF/DKIM authentication'=>'SPF/DKIM تصدیق درکار کریں','When enabled, intake messages must pass SPF or DKIM authentication (via the Authentication-Results header). Prevents spoofed From: addresses. Requires your ESP to include Authentication-Results headers and your domain to have SPF/DKIM records configured. Leave off if you are not sure — rejected legitimate mail is silent. Default: off.'=>'جب یہ فعال ہو، intake پیغامات کو SPF یا DKIM تصدیق (Authentication-Results ہیڈر کے ذریعے) پاس کرنا ضروری ہے۔ یہ جعلسازی شدہ From: پتے روکتا ہے۔ اس کے لیے ضروری ہے کہ آپ کا ESP Authentication-Results ہیڈرز شامل کرے اور آپ کے ڈومین پر SPF/DKIM records configured ہوں۔ اگر یقین نہ ہو تو اسے بند رکھیں — درست میل کا مسترد ہونا خاموش ہوتا ہے۔ طے شدہ: بند۔','Description provider'=>'وضاحت فراہم کنندہ','Analyzes the artwork image and writes the title, body, tags and alt text. WordPress AI Services delegates to whichever provider the site has configured via the AI Services plugin.'=>'آرٹ ورک کی تصویر کا تجزیہ کرتا ہے اور عنوان، متن، ٹیگز اور alt text لکھتا ہے۔ WordPress AI Services اسی فراہم کنندہ کو delegation دیتا ہے جو سائٹ نے AI Services plugin کے ذریعے configure کیا ہو۔','OpenAI vision model'=>'OpenAI وژن ماڈل','Model used for artwork description when OpenAI is the description provider. Must support vision input.'=>'جب OpenAI وضاحت فراہم کنندہ ہو تو آرٹ ورک کی وضاحت کے لیے استعمال ہونے والا ماڈل۔ اسے vision input کی حمایت کرنی چاہیے۔','Anthropic model'=>'Anthropic ماڈل','Model used for artwork description when Anthropic is the description provider. Must support vision input.'=>'Anthropic کو جب وضاحتی فراہم کنندہ کے طور پر استعمال کیا جائے تو فن پارے کی وضاحت کے لیے استعمال ہونے والا ماڈل۔ ویژن اِن پٹ کو سپورٹ کرنا ضروری ہے۔','OpenAI text model'=>'OpenAI text model','Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when OpenAI is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Anthropic text model'=>'Anthropic text model','Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.'=>'Cheap, fast model used for text-only tasks when Anthropic is the description provider — translating a submission into the site\'s primary language, and moderating contact-form messages. Does not need vision support.','Vision image max width (px)'=>'ویژن امیج کی زیادہ سے زیادہ چوڑائی (px)','Images are downscaled proportionally to this width before being sent to the AI for description — vision token cost scales with resolution, and a description task needs far fewer pixels than the original photo. Applies to artwork photo uploads, rasterised PDF pages, and video poster frames alike. Set to 0 to always send full-resolution images (uses more tokens, no quality difference for typical description tasks). Requires the Imagick PHP extension; images are sent at their original size regardless of this setting when it is unavailable. Default: 800.'=>'تصاویر کو AI کو وضاحت کے لیے بھیجنے سے پہلے تناسب کے ساتھ اس چوڑائی تک کم کیا جاتا ہے — ویژن ٹوکن لاگت ریزولوشن کے ساتھ بڑھتی ہے، اور وضاحتی کام کے لیے اصل تصویر کے مقابلے میں کہیں کم پکسلز درکار ہوتے ہیں۔ یہ آرٹ ورک فوٹو اپ لوڈز، راسٹرائزڈ PDF صفحات، اور ویڈیو پوسٹر فریمز سب پر لاگو ہوتا ہے۔ 0 پر سیٹ کریں تاکہ ہمیشہ مکمل ریزولوشن تصاویر بھیجی جائیں (زیادہ ٹوکن استعمال ہوں گے، مگر عام وضاحتی کاموں میں معیار میں کوئی فرق نہیں ہوگا)۔ اس کے لیے Imagick PHP extension درکار ہے؛ جب یہ دستیاب نہ ہو تو تصاویر اس ترتیب سے قطع نظر اپنی اصل سائز میں بھیجی جاتی ہیں۔ طے شدہ: 800.','Enhancement provider'=>'بہتری فراہم کرنے والا','Auto (OpenAI if key is set)'=>'خودکار (اگر کی موجود ہو تو OpenAI)','Disabled — use original image'=>'غیر فعال — اصل تصویر استعمال کریں','Enhances the artwork image before publishing. Uses OpenAI gpt-image-1. Set to Disabled to skip enhancement and publish the original.'=>'شائع کرنے سے پہلے فن پارے کی تصویر کو بہتر بناتا ہے۔ OpenAI gpt-image-1 استعمال کرتا ہے۔ بہتر سازی چھوڑنے اور اصل تصویر شائع کرنے کے لیے Disabled پر سیٹ کریں۔','OpenAI image model'=>'OpenAI امیج ماڈل','Model used for image enhancement when OpenAI is the enhancement provider.'=>'OpenAI کو امیج اینہانسمنٹ فراہم کنندہ کے طور پر استعمال کرنے کی صورت میں تصویر بہتر بنانے کے لیے استعمال ہونے والا ماڈل۔','Polish biography with AI'=>'AI کے ساتھ سوانحِ حیات کو درست و بہتر بنائیں','When enabled, biography submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'جب یہ فعال ہو، سوانحِ حیات کی گذارشات کو محفوظ کرنے سے پہلے AI کے ذریعے گزارا جاتا ہے تاکہ املا درست ہو جائے اور متن میں معمولی بہتری آ جائے۔','Polish events with AI'=>'AI کے ساتھ ایونٹس کو درست و بہتر بنائیں','When enabled, event submissions are passed through the AI to fix spelling and make minor text improvements before saving.'=>'جب یہ فعال ہو، ایونٹ کی گذارشات کو محفوظ کرنے سے پہلے AI کے ذریعے گزارا جاتا ہے تاکہ املا درست ہو جائے اور متن میں معمولی بہتری آ جائے۔','Merge biography updates with AI'=>'AI کے ساتھ سوانحِ حیات کی تازہ کاریوں کو ضم کریں','When enabled, biography updates are merged with the existing biography using AI — new information is integrated rather than replacing everything. Recommended: artists can send incremental updates ("I just won an award") without resubmitting their full bio. Disable to always replace the biography with the latest submission.'=>'جب یہ فعال ہو، سوانحِ حیات کی تازہ کاریاں موجودہ سوانحِ حیات کے ساتھ AI کی مدد سے ضم کی جاتی ہیں — نئی معلومات شامل کر دی جاتی ہے، سب کچھ بدلنے کے بجائے۔ تجویز: فنکار بتدریج تازہ کاریاں بھیج سکتے ہیں ("میں نے ابھی ایک ایوارڈ جیتا ہے") بغیر اپنی پوری بایو دوبارہ جمع کرائے۔ اگر ہمیشہ سوانحِ حیات کو تازہ ترین گذارش سے بدلنا ہو تو اسے غیر فعال کریں۔','Rejection threshold (quality score)'=>'رد کرنے کی حد (کوالٹی اسکور)','Photos scoring at or below this value (1–10) are automatically rejected — the artist receives a friendly email explaining the issue and is invited to resubmit. Score 0 disables automatic rejection. Must be lower than the enhancement threshold. Default: 3.'=>'اس قدر یا اس سے کم اسکور والی تصاویر (1–10) خود بخود رد کر دی جاتی ہیں — فنکار کو مسئلے کی وضاحت کے ساتھ ایک دوستانہ ای میل موصول ہوتی ہے اور اسے دوبارہ جمع کرانے کی دعوت دی جاتی ہے۔ اسکور 0 خودکار رد کو غیر فعال کرتا ہے۔ یہ اینہانسمنٹ حد سے کم ہونا چاہیے۔ طے شدہ: 3۔','Enhancement threshold (quality score)'=>'بہتری کی حد (کوالٹی اسکور)','Photos scoring below this value (1–10) are automatically enhanced. Score 10 = perfect photograph, 1 = technically unusable. Default: 7 — only visibly problematic photos are processed. Set to 1 to disable automatic enhancement entirely.'=>'اس قدر سے کم اسکور والی تصاویر (1–10) خود بخود بہتر کی جاتی ہیں۔ اسکور 10 = بہترین تصویر، 1 = تکنیکی طور پر ناقابلِ استعمال۔ طے شدہ: 7 — صرف واضح طور پر مسئلہ والی تصاویر پروسیس ہوتی ہیں۔ خودکار بہتری مکمل طور پر غیر فعال کرنے کے لیے اسے 1 پر سیٹ کریں۔','OpenAI API key'=>'OpenAI API کلید','Required when OpenAI is the description or enhancement provider.'=>'جب OpenAI وضاحت یا اینہانسمنٹ فراہم کنندہ ہو تو درکار ہے۔','Anthropic API key'=>'Anthropic API کلید','Required when Anthropic is the description provider.'=>'جب Anthropic وضاحت فراہم کنندہ ہو تو درکار ہے۔','Artwork display width (px)'=>'آرٹ ورک ڈسپلے چوڑائی (px)','Width of the agnosis-artwork image size used in post content and lightbox. Height scales proportionally. Default: 1920. Existing images need to be regenerated after changing this value.'=>'پوسٹ مواد اور لائٹ باکس میں استعمال ہونے والے agnosis-artwork امیج سائز کی چوڑائی۔ اونچائی تناسب کے مطابق بدلتی ہے۔ طے شدہ: 1920۔ یہ قدر بدلنے کے بعد موجودہ تصاویر کو دوبارہ جنریٹ کرنا ہوگا۔','Thumbnail size (px)'=>'تھمب نیل سائز (px)','Side length of the square agnosis-thumb size used in submission cards and dashboard. Default: 512. Existing images need to be regenerated after changing this value.'=>'سبمیشن کارڈز اور ڈیش بورڈ میں استعمال ہونے والے مربع agnosis-thumb سائز کی ہر طرف کی لمبائی۔ طے شدہ: 512۔ یہ قدر بدلنے کے بعد موجودہ تصاویر کو دوبارہ جنریٹ کرنا ہوگا۔','Email image width (px)'=>'ای میل تصویر چوڑائی (px)','Width of the agnosis-email size used in artist notification emails. Height scales proportionally — no cropping. Default: 420. Existing images need to be regenerated after changing this value.'=>'فنکاروں کی اطلاع والی ای میلز میں استعمال ہونے والے agnosis-email سائز کی چوڑائی۔ اونچائی تناسب کے مطابق بدلتی ہے — کوئی کراپنگ نہیں۔ طے شدہ: 420۔ یہ قدر بدلنے کے بعد موجودہ تصاویر کو دوبارہ جنریٹ کرنا ہوگا۔','Gallery overview — items per page'=>'گیلری جائزہ — فی صفحہ آئٹمز','How many artwork cards the gallery overview shows per page. Pool is built proportionally across all artists; featured artworks are preferred. Default: 12.'=>'گیلری جائزہ فی صفحہ کتنے آرٹ ورک کارڈز دکھاتا ہے۔ پول تمام فنکاروں میں متناسب طور پر بنایا جاتا ہے؛ نمایاں آرٹ ورکس کو ترجیح دی جاتی ہے۔ طے شدہ: 12۔','Review link expiry (days)'=>'جائزہ لنک کی میعاد ختم ہونے کی مدت (دن)','How long the Approve & Publish / Discard links in a submission review email stay valid before an artist has to log in to manage the item instead. Applies uniformly to artwork, biography, and event drafts. Default: 7.'=>'منظور کریں اور شائع کریں / مسترد کریں لنکس، جو سبمیشن ریویو ای میل میں ہوتے ہیں، کتنے عرصے تک درست رہتے ہیں اس سے پہلے کہ فنکار کو آئٹم منظم کرنے کے لیے لاگ اِن کرنا پڑے۔ یہ آرٹ ورک، سوانحِ حیات، اور ایونٹ ڈرافٹس سب پر یکساں لاگو ہوتا ہے۔ طے شدہ: 7۔','System prompt'=>'سسٹم پرامپٹ','Sent to the AI as the system instruction. Use {tag_count} and {excerpt_words} as tokens — they are replaced with the values below.'=>'AI کو سسٹم ہدایت کے طور پر بھیجا جاتا ہے۔ {tag_count} اور {excerpt_words} کو ٹوکنز کے طور پر استعمال کریں — ان کی جگہ نیچے دی گئی قدریں لے لی جاتی ہیں۔','Artist prompt template'=>'فنکار پرامپٹ ٹیمپلیٹ','User message sent alongside the artwork image. Use {artist_prompt} where the artist\'s own description should appear.'=>'آرٹ ورک تصویر کے ساتھ بھیجا جانے والا یوزر میسج۔ جہاں فنکار کی اپنی وضاحت ہونی چاہیے وہاں {artist_prompt} استعمال کریں۔','Enhancement instructions'=>'بہتری کی ہدایات','Instructions passed to the image enhancement provider. The AI-generated artwork description is appended automatically as context.'=>'امیج اینہانسمنٹ فراہم کنندہ کو بھیجی جانے والی ہدایات۔ AI سے تیار کردہ آرٹ ورک کی وضاحت خودکار طور پر سیاق و سباق کے طور پر شامل کر دی جاتی ہے۔','Number of tags'=>'ٹیگز کی تعداد','How many tags the AI should generate per artwork. Referenced as {tag_count} in the system prompt.'=>'AI کو ہر آرٹ ورک کے لیے کتنے ٹیگز بنانے چاہییں۔ سسٹم پرامپٹ میں اسے {tag_count} کے طور پر استعمال کیا جاتا ہے۔','Excerpt word limit'=>'اقتباس کے الفاظ کی حد','Maximum words for the one-sentence excerpt. Referenced as {excerpt_words} in the system prompt.'=>'ایک جملے والے اقتباس کے لیے زیادہ سے زیادہ الفاظ۔ سسٹم پرامپٹ میں اسے {excerpt_words} کے طور پر استعمال کیا جاتا ہے۔','Trust all admitted artists (skip link review entirely)'=>'تمام منظور شدہ فنکاروں پر اعتماد کریں (لنک ریویو مکمل طور پر چھوڑ دیں)','Every artist here was already vouched in by the community — if that trust is enough for you, turn this on to embed any link an artist submits, immediately, with no allowlist check and no AI review at all (the settings below are skipped entirely while this is on). Off by default. Only enable this if you are comfortable that a bad actor who made it through admission could embed a link to anything.'=>'یہاں ہر فنکار کو کمیونٹی پہلے ہی قابلِ اعتماد قرار دے چکی ہے — اگر یہ اعتماد آپ کے لیے کافی ہے تو اسے آن کر دیں تاکہ کوئی بھی لنک جو فنکار بھیجے، فوراً ایمبیڈ ہو جائے، بغیر کسی allowlist چیک اور بغیر کسی AI ریویو کے (جب یہ آن ہو تو نیچے دی گئی سیٹنگز مکمل طور پر چھوڑ دی جاتی ہیں)۔ ڈیفالٹ: آف۔ اسے صرف اسی صورت میں فعال کریں جب آپ اس بات پر مطمئن ہوں کہ داخلہ حاصل کر لینے والا کوئی بد نیت شخص کسی بھی چیز کا لنک ایمبیڈ کر سکتا ہے۔','Trusted embed platforms'=>'قابلِ اعتماد ایمبیڈ پلیٹ فارم','One hostname per line. A submitted link becomes a rich embed immediately if it matches one of these (or a subdomain of one) — no AI review needed, no network request made to the link itself.'=>'ہر لائن میں ایک hostname۔ بھیجا گیا لنک فوراً ایک رچ ایمبیڈ بن جاتا ہے اگر وہ ان میں سے کسی سے (یا اس کے subdomain سے) میل کھائے — AI ریویو کی ضرورت نہیں، اور خود لنک پر کوئی نیٹ ورک درخواست نہیں کی جاتی۔','Let artists submit other links too (AI-reviewed)'=>'فنکاروں کو دوسرے لنکس بھی جمع کرانے دیں (AI ریویو کے ساتھ)','When enabled, a link to a site not on the trusted list above is not simply discarded: the destination page is fetched and reviewed by your configured AI provider (Settings → AI Providers) against the categories below before deciding whether to embed it. If the AI cannot be reached, the request times out, or the page cannot be safely fetched, the link is not embedded — it fails safe. When disabled (the default), only the trusted platforms above are ever embedded.'=>'جب یہ فعال ہو، تو اوپر دی گئی قابلِ اعتماد فہرست میں شامل نہ ہونے والی سائٹ کا لنک محض رد نہیں کیا جاتا: منزل والا صفحہ حاصل کیا جاتا ہے اور آپ کے ترتیب دیے گئے AI فراہم کنندہ (سیٹنگز → AI Providers) کے ذریعے نیچے دی گئی کیٹیگریز کے خلاف جانچا جاتا ہے، پھر فیصلہ کیا جاتا ہے کہ اسے ایمبیڈ کرنا ہے یا نہیں۔ اگر AI دستیاب نہ ہو، درخواست وقت ختم ہو جائے، یا صفحہ محفوظ طریقے سے حاصل نہ کیا جا سکے، تو لنک ایمبیڈ نہیں ہوتا — یہ محفوظ طور پر ناکام ہوتا ہے۔ جب یہ غیر فعال ہو (ڈیفالٹ)، صرف اوپر دیے گئے قابلِ اعتماد پلیٹ فارمز ہی ایمبیڈ ہوتے ہیں۔','Block pornographic / sexually explicit content'=>'فحش / جنسی طور پر واضح مواد کو بلاک کریں','Only takes effect when AI review (above) is enabled.'=>'صرف تب مؤثر ہوتا ہے جب AI ریویو (اوپر) فعال ہو۔','Block primarily commercial / promotional sites'=>'زیادہ تر تجارتی / پروموشنل سائٹس کو بلاک کریں','Online stores, advertising, marketing landing pages. Off by default — an artist linking to a shop selling their own prints is common and not inherently unwanted. Only takes effect when AI review (above) is enabled.'=>'آن لائن اسٹورز، اشتہاری، مارکیٹنگ لینڈنگ پیجز۔ ڈیفالٹ: آف — کسی فنکار کا اپنی پرنٹس بیچنے والی دکان کا لنک دینا عام بات ہے اور خود میں ناپسندیدہ نہیں۔ صرف تب مؤثر ہوتا ہے جب AI ریویو (اوپر) فعال ہو۔','Block gambling / betting sites'=>'جوا / شرط لگانے والی سائٹس کو بلاک کریں','Additional disallowed categories'=>'اضافی ممنوعہ زمرے','Optional — describe any other kind of content the AI should reject, in plain language (e.g. "hate speech or violent extremist content", "phishing or scam pages"). Only takes effect when AI review (above) is enabled.'=>'اختیاری — سادہ زبان میں بیان کریں کہ AI کو کس قسم کے مزید مواد کو رد کرنا چاہیے (مثلاً "نفرت انگیز تقریر یا پرتشدد انتہاپسندانہ مواد"، "فِشنگ یا اسکام صفحات")۔ صرف تب مؤثر ہوتا ہے جب AI ریویو (اوپر) فعال ہو۔','Node label'=>'نوڈ لیبل','How this node introduces itself to the network.'=>'یہ نوڈ نیٹ ورک کے سامنے خود کو کیسے متعارف کراتا ہے۔','Enable ActivityPub federation'=>'ActivityPub فیڈریشن کو فعال کریں','Broadcast new artworks to Mastodon, Pixelfed and the Fediverse.'=>'نئے فن پارے Mastodon، Pixelfed اور Fediverse پر نشر کریں۔','Node public key'=>'نوڈ کی عوامی کلید','Auto-generated RSA public key for this node. Share this with peer nodes.'=>'اس نوڈ کے لیے خودکار طور پر بنائی گئی RSA عوامی کلید۔ اسے ہم منصب نوڈز کے ساتھ شیئر کریں۔','Self-removal (goodbye) requests per sender per day'=>'ہر بھیجنے والے کے لیے فی دن خود-اخراج (الوداع) درخواستیں','Maximum number of self-removal ("goodbye") confirmation emails a single sender address can trigger per day. A genuine self-removal only ever needs to be requested once — this caps how many confirmation emails a spoofed or repeated From can be used to spam a real artist with. Default: 3.'=>'ایک واحد بھیجنے والے کے پتے سے فی دن زیادہ سے زیادہ کتنی خود-اخراج ("الوداع") تصدیقی ای میلز شروع کی جا سکتی ہیں۔ حقیقی خود-اخراج کی درخواست صرف ایک بار کرنی ہوتی ہے — یہ اس بات کی حد مقرر کرتا ہے کہ نقلی یا بار بار بھیجے گئے From کے ذریعے کسی حقیقی فنکار کو کتنی تصدیقی ای میلز سے اسپام کیا جا سکتا ہے۔ پہلے سے طے شدہ: 3۔','Community broadcasts per artist per day'=>'فی فنکار فی دن کمیونٹی براڈکاسٹس','Maximum number of messages a single artist can send to the Community announcement address (Settings → Email) per day. Prevents one member from flooding every other member\'s inbox. Default: 3.'=>'ایک واحد فنکار روزانہ Settings → Email میں موجود Community announcement پتے پر زیادہ سے زیادہ کتنے پیغامات بھیج سکتا ہے۔ یہ ایک رکن کو باقی تمام ارکان کے ان باکس بھرنے سے روکتا ہے۔ پہلے سے طے شدہ: 3۔','Community broadcast max length (characters)'=>'کمیونٹی براڈکاسٹ کی زیادہ سے زیادہ لمبائی (حروف)','Longer messages to the Community announcement address are bounced back to the sender instead of being broadcast — the sender is told to shorten it and resend. Measured in characters, not words, so it applies fairly across languages that don\'t use spaces between words (Chinese, Japanese, Thai, etc.). Every recipient\'s copy is translated individually, so this also caps how much a single message can cost in AI translation calls. Default: 2000. Hard maximum: 20000, regardless of this setting.'=>'Community announcement پتے پر بھیجے گئے طویل پیغامات براڈکاسٹ ہونے کے بجائے بھیجنے والے کو واپس کر دیے جاتے ہیں — بھیجنے والے کو کہا جاتا ہے کہ اسے مختصر کر کے دوبارہ بھیجے۔ پیمائش الفاظ میں نہیں بلکہ حروف میں کی جاتی ہے، اس لیے یہ ان زبانوں پر بھی منصفانہ طور پر لاگو ہوتا ہے جن میں الفاظ کے درمیان اسپیس نہیں ہوتیں (چینی، جاپانی، تھائی، وغیرہ)۔ ہر وصول کنندہ کی کاپی انفرادی طور پر ترجمہ کی جاتی ہے، لہٰذا یہ اس بات کی بھی حد مقرر کرتا ہے کہ ایک واحد پیغام AI ترجمہ کالز میں کتنا خرچ کرا سکتا ہے۔ پہلے سے طے شدہ: 2000۔ سخت زیادہ سے زیادہ: 20000، اس ترتیب سے قطع نظر۔','Admission vote threshold (%)'=>'داخلہ ووٹ کی حد (%)','Percentage of active artists that must vote yes for admission. Combined with the minimum floor below.'=>'فعال فنکاروں کا وہ فیصد جن کا داخلے کے حق میں ہاں میں ووٹ دینا ضروری ہے۔ ذیل میں دی گئی کم از کم حد کے ساتھ مل کر۔','Admission minimum votes'=>'داخلے کے لیے کم از کم ووٹ','Absolute minimum positive votes required regardless of the percentage above.'=>'اوپر دیے گئے فیصد سے قطع نظر درکار مثبت ووٹوں کی قطعی کم از کم تعداد۔','Voting window (days)'=>'ووٹنگ کی مدت (دن)','Days an application stays open. If the threshold is not reached within this window the application is rejected.'=>'درخواست جتنے دن کھلی رہتی ہے۔ اگر اس مدت کے اندر حد پوری نہ ہو تو درخواست مسترد کر دی جاتی ہے۔','Resolved application retention (days)'=>'حل شدہ درخواست کی برقراری (دن)','A rejected, withdrawn, or left application\'s email, name, biography, statement, and portfolio link are anonymized by the daily cleanup after this many days — the application record itself (status and dates) is kept for admission history. A banned artist\'s biography/statement/portfolio are anonymized on the same schedule, but their email is deliberately kept so the ban stays enforceable. Default: 180 days.'=>'مسترد، واپس لی گئی، یا چھوڑ دی گئی درخواست کی ای میل، نام، سوانح، بیان، اور پورٹ فولیو لنک کو اتنے دنوں کے بعد روزانہ صفائی کے عمل میں گمنام کر دیا جاتا ہے — خود درخواست کا ریکارڈ (اسٹیٹس اور تاریخیں) داخلہ تاریخ کے لیے محفوظ رہتا ہے۔ پابندی شدہ فنکار کی سوانح/بیان/پورٹ فولیو اسی شیڈول کے مطابق گمنام کیے جاتے ہیں، لیکن ان کی ای میل جان بوجھ کر محفوظ رکھی جاتی ہے تاکہ پابندی نافذ رہ سکے۔ پہلے سے طے شدہ: 180 دن۔','After applying, send artists to'=>'درخواست دینے کے بعد فنکاروں کو بھیجیں','Optional — pick a page explaining the vouching process and what happens next. When the application is submitted successfully, the artist is redirected there instead of just seeing an inline confirmation message. Leave as "None" to keep the inline message only.'=>'اختیاری — ایک ایسا صفحہ منتخب کریں جو واؤچنگ کے عمل اور اگلا مرحلہ بیان کرتا ہو۔ جب درخواست کامیابی سے جمع ہو جاتی ہے، تو فنکار کو صرف اندرونی تصدیقی پیغام دیکھنے کے بجائے وہاں منتقل کر دیا جاتا ہے۔ صرف اندرونی پیغام برقرار رکھنے کے لیے "None" ہی رہنے دیں۔','Community size cap'=>'کمیونٹی سائز کی حد','Maximum number of admitted artists. When full, new applications join a waitlist instead of being rejected, and a freed slot admits the next in line. Set to 0 for no cap. The community can also vote to change this.'=>'داخل شدہ فنکاروں کی زیادہ سے زیادہ تعداد۔ جب حد پوری ہو جائے تو نئی درخواستیں مسترد ہونے کے بجائے ویٹ لسٹ میں شامل ہو جاتی ہیں، اور خالی ہونے والی جگہ پر اگلا منتظر شخص شامل ہو جاتا ہے۔ بغیر حد کے لیے 0 مقرر کریں۔ کمیونٹی اسے بدلنے کے لیے ووٹ بھی دے سکتی ہے۔','Cap-change co-signers required'=>'حد بدلنے کے لیے مطلوبہ کو-سائنرز','How many artists must co-sign a proposal to change the community size cap before it opens as a full community vote.'=>'کمیونٹی سائز کی حد تبدیل کرنے کی تجویز کو مکمل کمیونٹی ووٹ بننے سے پہلے کتنے فنکاروں کو اس کی مشترکہ توثیق کرنی ہوگی۔','Cap-change vote window (days)'=>'حد بدلنے کے ووٹ کی مدت (دن)','Days a community cap-change vote stays open. A strict majority of active artists voting yes adopts the new cap.'=>'کمیونٹی کی حد بدلنے کے ووٹ کے کھلے رہنے کے دن۔ فعال فنکاروں کی سادہ اکثریت کے ہاں ووٹ دینے پر نئی حد نافذ ہو جاتی ہے۔','Removal nominations required'=>'اخراج کے لیے درکار نامزدگیاں','Number of artist nominations needed before a community removal vote opens. Admins can bypass this threshold.'=>'کمیونٹی اخراج کے ووٹ کے آغاز سے پہلے کتنی فنکار نامزدگیاں درکار ہیں۔ منتظمین اس حد کو نظر انداز کر سکتے ہیں۔','Removal vote window (days)'=>'اخراج کے ووٹ کی مدت (دن)','Days a community removal vote stays open. A majority (>50%) of active artists must vote yes for removal to proceed.'=>'کمیونٹی اخراج کے ووٹ کے کھلے رہنے کے دن۔ اخراج کے لیے فعال فنکاروں کی اکثریت (>50%) کا ہاں میں ووٹ دینا ضروری ہے۔','Invitation intro'=>'دعوت کا تعارفی متن','Agnosis is a small, self-hosted home for artists who\'d rather make work than manage a platform. There\'s no algorithm deciding who sees your art, no portfolio site to maintain, and no account to configure — just your work, published and translated automatically for a global audience.

Being part of the community is simple: Fellow artists vouch for new applicants, and everyone keeps full ownership of what they publish; you can leave at any time and take your work with you.

Once admitted, you submit new work by sending it as an email — no dashboard, no forms and you can update, promote or remove your artwork as well sending an email. You can find more information visiting the agnosis.art website.'=>'Agnosis فنکاروں کے لیے ایک چھوٹا، خود میزبان گھر ہے جو پلیٹ فارم سنبھالنے کے بجائے کام تخلیق کرنا پسند کرتے ہیں۔ یہاں کوئی الگورتھم نہیں جو طے کرے کہ آپ کا فن کون دیکھے، نہ کوئی پورٹ فولیو سائٹ جس کی دیکھ بھال کرنی پڑے، نہ کوئی اکاؤنٹ جسے ترتیب دینا ہو — بس آپ کا کام، خودکار طور پر شائع اور ایک عالمی ناظرین کے لیے ترجمہ ہو جاتا ہے۔

کمیونٹی کا حصہ بننا آسان ہے: ساتھی فنکار نئے درخواست دہندگان کی توثیق کرتے ہیں، اور ہر کوئی اپنی شائع کردہ چیزوں کی مکمل ملکیت رکھتا ہے؛ آپ کسی بھی وقت جا سکتے ہیں اور اپنا کام ساتھ لے جا سکتے ہیں۔

داخلے کے بعد، آپ اپنا نیا کام ای میل کے ذریعے بھیج کر جمع کرواتے ہیں — نہ ڈیش بورڈ، نہ فارم، اور آپ ای میل بھیج کر اپنے فن پارے کو اپ ڈیٹ، پروموٹ یا ہٹا بھی سکتے ہیں۔ مزید معلومات کے لیے آپ agnosis.art ویب سائٹ پر جا سکتے ہیں۔','Shown near the top of the "Send Invitation" email below (an "Apply to join" link and site name follow automatically — no need to add either here). Two or three short paragraphs is plenty. Standing copy, not cleared after use like the newsletter intros above — translated automatically when an invitation is sent in a language other than the site\'s own.'=>'نیچے دی گئی "دعوت بھیجیں" ای میل کے اوپر دکھایا جاتا ہے (ایک "شامل ہونے کے لیے درخواست دیں" لنک اور سائٹ کا نام خود بخود بعد میں آتے ہیں — انہیں یہاں شامل کرنے کی ضرورت نہیں)۔ دو یا تین مختصر پیراگراف کافی ہیں۔ مستقل عبارت، اوپر دیے گئے نیوز لیٹر تعارفی متن کی طرح استعمال کے بعد صاف نہیں کی جاتی — جب دعوت سائٹ کی اپنی زبان کے علاوہ کسی دوسری زبان میں بھیجی جائے تو یہ خودکار طور پر ترجمہ ہو جاتی ہے۔','Transaction fee (%)'=>'لین دین فیس (%)','Percentage retained by this node on donations and art sales. Artists pay nothing up front.'=>'عطیات اور فن پاروں کی فروخت پر اس نوڈ کے پاس رکھی جانے والی فیصد۔ فنکار پیشگی کچھ ادا نہیں کرتے۔','Sender name'=>'بھیجنے والے کا نام','Name shown as the sender of digest emails. Leave blank to use the site name.'=>'ڈائجسٹ ای میلز کے بھیجنے والے کے طور پر دکھایا جانے والا نام۔ سائٹ کا نام استعمال کرنے کے لیے خالی چھوڑ دیں۔','Sender email address'=>'بھیجنے والے کا ای میل پتہ','Dedicated From: address for both newsletters, e.g. newsletter@agnosis.art — keeps digest mail separate from the site\'s admin email for deliverability and so artists can filter it. Leave blank to use the admin email. Must be a valid, deliverable address on your domain (SPF/DKIM configured) or messages may be marked as spam.'=>'دونوں نیوزلیٹرز کے لیے مخصوص From: پتہ، مثلاً newsletter@agnosis.art — ڈائجسٹ میل کو سائٹ کے ایڈمن ای میل سے الگ رکھتا ہے تاکہ ڈیلیوری بہتر ہو اور فنکار اسے فلٹر کر سکیں۔ ایڈمن ای میل استعمال کرنے کے لیے خالی چھوڑ دیں۔ یہ آپ کے ڈومین پر ایک درست، قابلِ ترسیل پتہ ہونا چاہیے (SPF/DKIM کنفیگرڈ) ورنہ پیغامات اسپیم کے طور پر نشان زد ہو سکتے ہیں۔','Auto-draft newsletter intros'=>'نیوزلیٹر کے تعارفی متن کی خودکار ڈرافٹنگ','When enabled, Agnosis drafts an intro via AI ahead of each issue (see the lead time below), saves it to that newsletter\'s intro field, and emails you to review it — unless you\'ve already written one for that cycle. Disable to leave both intro fields exactly as you left them, always.'=>'جب یہ فعال ہو، تو Agnosis ہر شمارے سے پہلے AI کے ذریعے ایک تعارفی متن کا مسودہ تیار کرتا ہے (نیچے دی گئی لیڈ ٹائم دیکھیں)، اسے اس نیوزلیٹر کے intro فیلڈ میں محفوظ کرتا ہے، اور آپ کو اسے دیکھنے کے لیے ای میل کرتا ہے — مگر تب نہیں جب آپ نے پہلے ہی اس چکر کے لیے ایک لکھ رکھا ہو۔ اسے غیر فعال کریں تاکہ دونوں intro فیلڈز بالکل ویسے ہی رہیں جیسے آپ نے انہیں چھوڑا تھا، ہمیشہ۔','Draft intro this many hours ahead'=>'یہ تعارفی مسودہ کتنے گھنٹے پہلے تیار کیا جائے','How long before an issue is due Agnosis proposes an AI-drafted intro. Only takes effect when auto-drafting (above) is enabled. Default: 24.'=>'کوئی شمارہ مقرر ہونے سے کتنے وقت پہلے Agnosis AI سے تیار کردہ تعارف تجویز کرے۔ یہ صرف تب مؤثر ہوتا ہے جب اوپر والا خودکار ڈرافٹنگ فعال ہو۔ پہلے سے طے شدہ: 24۔','Artist newsletter'=>'فنکاروں کا نیوزلیٹر','Admitted artists are auto-enrolled (they can unsubscribe from any issue with one click). Community digest: recent activity, new members, open votes.'=>'جن فنکاروں کو قبول کیا گیا ہے انہیں خودکار طور پر شامل کر لیا جاتا ہے (وہ کسی بھی شمارے سے ایک کلک میں ان سبسکرائب کر سکتے ہیں)۔ کمیونٹی ڈائجسٹ: حالیہ سرگرمی، نئے اراکین، کھلی ووٹنگز۔','Artist newsletter frequency (days)'=>'فنکاروں کے نیوزلیٹر کی فریکوئنسی (دن)','Default 30 ≈ monthly. A new issue is prepared once this many days have passed since the last one was sent.'=>'پہلے سے طے شدہ 30 ≈ ماہانہ۔ جب پچھلا شمارہ بھیجے جانے کے بعد اتنے دن گزر جاتے ہیں تو نیا شمارہ تیار کیا جاتا ہے۔','Artist newsletter intro'=>'فنکاروں کے نیوزلیٹر کا تعارف','Optional note prepended to the next artist issue only — cleared automatically once that issue is queued. Leave blank to send the auto-digest with no intro. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'اگلے آرٹسٹ شمارے کے لیے صرف ایک اختیاری نوٹ — جیسے ہی وہ شمارہ قطار میں آتا ہے، یہ خود بخود صاف ہو جاتا ہے۔ اگر کوئی تعارف نہ ہو تو آٹو-ڈائجسٹ بھیجنے کے لیے خالی چھوڑ دیں۔ اگر خالی چھوڑا جائے تو Agnosis شمارے کے بھیجے جانے سے تقریباً ایک دن پہلے نئے مواد کی بنیاد پر خودکار طور پر ایک مسودہ بناتا ہے، اور پہلے اسے جانچنے کے لیے آپ کو ای میل بھی کرتا ہے — اسے چھوڑنے کے لیے یہاں کبھی بھی اپنا نوٹ لکھ دیں۔','Public newsletter'=>'عوامی نیوز لیٹر','Visitors subscribe via the agnosis/newsletter-signup block (double opt-in). Digest: new artwork and events published since the last issue.'=>'زائرین agnosis/newsletter-signup بلاک کے ذریعے سبسکرائب کرتے ہیں (ڈبل آپٹ اِن)۔ ڈائجسٹ: پچھلے شمارے کے بعد شائع ہونے والی نئی تخلیقات اور تقریبات۔','Public newsletter frequency (days)'=>'عوامی نیوز لیٹر کی فریکوئنسی (دن)','Default 30 ≈ monthly.'=>'ڈیفالٹ 30 ≈ ماہانہ۔','Public newsletter intro'=>'عوامی نیوز لیٹر کا تعارف','Optional note prepended to the next public issue only — cleared automatically once that issue is queued. If left blank, Agnosis drafts one automatically from what\'s new about a day before the issue sends, and emails you to review it first — write your own here any time to skip that.'=>'اگلے عوامی شمارے کے لیے صرف ایک اختیاری نوٹ — جیسے ہی وہ شمارہ قطار میں آتا ہے، یہ خود بخود صاف ہو جاتا ہے۔ اگر کوئی تعارف نہ ہو تو آٹو-ڈائجسٹ بھیجنے کے لیے خالی چھوڑ دیں۔ اگر خالی چھوڑا جائے تو Agnosis شمارے کے بھیجے جانے سے تقریباً ایک دن پہلے نئے مواد کی بنیاد پر خودکار طور پر ایک مسودہ بناتا ہے، اور پہلے اسے جانچنے کے لیے آپ کو ای میل بھی کرتا ہے — اسے چھوڑنے کے لیے یہاں کبھی بھی اپنا نوٹ لکھ دیں۔','Send batch size'=>'بھیجنے کے بیچ کا سائز','Recipients emailed per 5-minute cron tick. Lower this if your host throttles outbound mail; raise it for faster delivery on hosts with generous limits.'=>'ہر 5 منٹ کے کرون ٹِک پر ای میل کیے گئے وصول کنندگان۔ اگر آپ کا ہوسٹ آؤٹ باؤنڈ میل کو محدود کرتا ہے تو اسے کم کریں؛ اور اگر ہوسٹس کی حدیں زیادہ فراخ ہیں تو تیز تر ترسیل کے لیے اسے بڑھا دیں۔','Self-hosting comfort threshold'=>'خود ہوسٹنگ سہولت کی حد','Advisory only — self-hosted sending keeps working above this count. Once confirmed public subscribers pass it, this page shows a reminder to consider an email service provider (e.g. Brevo\'s free tier) instead.'=>'صرف مشورہ ہے — خود ہوسٹڈ بھیجنا اس تعداد سے اوپر بھی کام کرتا رہتا ہے۔ جب تصدیق شدہ عوامی سبسکرائبرز اس حد سے بڑھ جائیں تو یہ صفحہ آپ کو یاد دہانی دکھاتا ہے کہ اس کے بجائے ای میل سروس فراہم کنندہ (مثلاً Brevo کا مفت ٹائر) پر غور کریں۔','Sends a minimal ping ("Reply with the word: ping") using the configured API key.'=>'ایک مختصر پِنگ بھیجتا ہے ("جواب میں یہ لفظ لکھیں: ping")، ترتیب دی گئی API کلید کا استعمال کرتے ہوئے۔','Sends a minimal ping using the configured API key.'=>'ترتیب دی گئی API کلید کا استعمال کرتے ہوئے ایک مختصر پِنگ بھیجتا ہے۔','WordPress AI Client'=>'ورڈپریس AI کلائنٹ','Checks that wp_ai_client_prompt() is available (WordPress 7.0+) and a text-generation model is configured.'=>'چیک کرتا ہے کہ wp_ai_client_prompt() دستیاب ہے (WordPress 7.0+) اور ٹیکسٹ جنریشن ماڈل ترتیب دیا گیا ہے۔','Test AI Providers'=>'AI فراہم کنندگان کی جانچ کریں','Test %s'=>'%s کی جانچ کریں','Bot Protection'=>'بوٹ تحفظ','Turnstile is configured.'=>'Turnstile ترتیب دیا گیا ہے۔','The Join application form and the Newsletter Subscribe form both require human verification before they accept a submission.'=>'جوائن درخواست فارم اور نیوزلیٹر سبسکرائب فارم دونوں کسی بھی جمع کرانے کو قبول کرنے سے پہلے انسانی تصدیق چاہتے ہیں۔','Turnstile is not configured.'=>'Turnstile ترتیب نہیں دیا گیا۔','Your Join application form is public — anyone can submit an application, and a submitted (and confirmed) application still emails every admitted artist and admin. Right now the only thing standing between that form and an automated bot is a fixed 5-submissions-per-minute-per-IP limit, which a distributed bot can work around entirely. Add a Cloudflare Turnstile site key and secret key above to require human verification on both the Join form and the Newsletter Subscribe form.'=>'آپ کا جوائن درخواست فارم عوامی ہے — کوئی بھی درخواست جمع کرا سکتا ہے، اور جمع کرائی گئی (اور تصدیق شدہ) درخواست پھر بھی ہر منظور شدہ آرٹسٹ اور ایڈمن کو ای میل کرتی ہے۔ فی الحال اس فارم اور خودکار بوٹ کے درمیان صرف ایک چیز ہے: فی IP فی منٹ 5 جمع کرانے کی مقررہ حد، جسے ایک تقسیم شدہ بوٹ مکمل طور پر چکما دے سکتا ہے۔ اوپر Cloudflare Turnstile کی site key اور secret key شامل کریں تاکہ جوائن فارم اور نیوزلیٹر سبسکرائب فارم دونوں پر انسانی تصدیق لازم ہو جائے۔','OpenAI'=>'OpenAI','Anthropic'=>'Anthropic','AI Processing & Privacy Policy'=>'AI پروسیسنگ اور رازداری کی پالیسی','A Privacy Policy page is set.'=>'ایک رازداری کی پالیسی کا صفحہ سیٹ ہے۔','Suggested wording covering %s and public federation was added to it automatically — review it under Settings → Privacy → "Guide" before publishing, and check with your provider(s) about their own data processing agreement (DPA) for your compliance obligations.'=>'%s اور عوامی فیڈریشن کا احاطہ کرنے والی تجویز کردہ عبارت اس میں خودکار طور پر شامل کر دی گئی تھی — شائع کرنے سے پہلے اسے Settings → Privacy → "Guide" میں دیکھیں، اور اپنی تعمیل کی ذمہ داریوں کے لیے اپنے فراہم کنندہ/فراہم کنندگان سے ان کے اپنے data processing agreement (DPA) کے بارے میں بھی چیک کریں۔','No Privacy Policy page is set.'=>'کوئی رازداری کی پالیسی کا صفحہ سیٹ نہیں ہے۔','Submitted artwork, text, and visitor contact messages are sent to %s for processing. Create or choose a page under Settings → Privacy — this plugin has already prepared suggested wording you\'ll find there under "Guide". You may also want to review that provider\'s data processing agreement (DPA) for your own compliance obligations.'=>'جمع کرائی گئی تخلیق، متن، اور وزیٹر رابطہ پیغامات پروسیسنگ کے لیے %s کو بھیجے جاتے ہیں۔ Settings → Privacy میں ایک صفحہ بنائیں یا منتخب کریں — اس پلگ اِن نے پہلے ہی تجویز کردہ عبارت تیار کر دی ہے جو آپ کو وہاں "Guide" کے تحت ملے گی۔ آپ اپنی تعمیل کی ذمہ داریوں کے لیے اس فراہم کنندہ کے data processing agreement (DPA) کا بھی جائزہ لینا چاہیں گے۔','Go to Settings → Privacy'=>'Settings → Privacy پر جائیں','Debug Files'=>'ڈیبگ فائلیں','Currently'=>'فی الحال','Enabled'=>'فعال','Disabled'=>'غیر فعال','Forced ON by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'wp-config.php میں AGNOSIS_DEBUG constant کے ذریعے جبراً ON — جب تک وہ لائن ہٹا نہیں دی جاتی، اوپر والا چیک باکس بے اثر رہے گا۔','Forced OFF by the AGNOSIS_DEBUG constant in wp-config.php — the checkbox above has no effect until that line is removed.'=>'wp-config.php میں AGNOSIS_DEBUG constant کے ذریعے جبراً OFF — جب تک وہ لائن ہٹا نہیں دی جاتی، اوپر والا چیک باکس بے اثر رہے گا۔','Directory'=>'ڈائریکٹری','Filter with agnosis_debug_dir to redirect debug output elsewhere.'=>'ڈیبگ آؤٹ پٹ کو کہیں اور بھیجنے کے لیے agnosis_debug_dir سے فلٹر کریں۔','.txt file(s) in the directory'=>'ڈائریکٹری میں .txt فائل(یں)','Delete all .txt files in the debug directory? The directory itself stays in place so future debug writes still land cleanly.'=>'ڈیبگ ڈائریکٹری میں موجود تمام .txt فائلیں حذف کر دیں؟ ڈائریکٹری خود برقرار رہے گی تاکہ آئندہ ڈیبگ لکھائی صاف طور پر وہیں جائے۔','Clear Debug Files'=>'ڈیبگ فائلیں صاف کریں','Term Translation Cache'=>'ٹرم ترجمہ کیش','Cached translations'=>'کیش شدہ تراجم','AI-translated tag/medium term names, cached so the same term always gets the same translated label instead of a fresh AI phrasing per post. Renaming a term already clears its own cached entry automatically; use the button below only if a cached translation itself is wrong.'=>'AI سے ترجمہ شدہ ٹیگ/میڈیم ٹرم نام، کیش میں محفوظ رہتے ہیں تاکہ ایک ہی ٹرم کو ہر بار ایک ہی ترجمہ شدہ لیبل ملے، بجائے اس کے کہ ہر پوسٹ کے لیے نیا AI انداز ہو۔ کسی ٹرم کا نام بدلنے سے اس کی اپنی کیش شدہ اندراج خود بخود صاف ہو جاتی ہے؛ نیچے والا بٹن صرف تب استعمال کریں جب کیش شدہ ترجمہ خود غلط ہو۔','Clear every cached term translation? Nothing is deleted from your site — terms will simply be re-translated by AI the next time they\'re needed.'=>'ہر کیش شدہ ٹرم ترجمہ صاف کر دیں؟ آپ کی سائٹ سے کچھ حذف نہیں ہوتا — ضرورت پڑنے پر ٹرمز کو اگلی بار AI دوبارہ ترجمہ کرے گا۔','Clear Term Translation Cache'=>'ٹرم ترجمہ کیش صاف کریں','Pipeline Logs'=>'پائپ لائن لاگز','Clear all log entries?'=>'تمام لاگ اندراجات صاف کر دی جائیں؟','Clear All'=>'سب صاف کریں','%d entries total. Logs are pruned automatically according to the Inbox retention setting.'=>'کل %d اندراجات۔ لاگز Inbox retention کی ترتیب کے مطابق خود بخود صاف کیے جاتے ہیں۔','No log entries yet.'=>'ابھی تک کوئی لاگ اندراجات نہیں۔','Time'=>'وقت','Level'=>'سطح','Context'=>'سیاق','Inbox Tools'=>'ان باکس ٹولز','Test connection'=>'کنکشن کی جانچ کریں','Test IMAP Connection'=>'IMAP کنکشن کی جانچ کریں','Connects to the configured mailbox and reports the total and unseen message count.'=>'ترتیب شدہ میل باکس سے جڑتا ہے اور کل اور غیر دیکھی گئی پیغامات کی تعداد بتاتا ہے۔','Poll inbox now'=>'ابھی ان باکس پول کریں','Poll Inbox Now'=>'ابھی ان باکس پول کریں','Fetches unseen messages immediately without waiting for WP-Cron. Then click "Process Pending Queue" to run the AI pipeline.'=>'WP-Cron کا انتظار کیے بغیر فوراً غیر دیکھی گئی پیغامات حاصل کرتا ہے۔ پھر AI پائپ لائن چلانے کے لیے "Process Pending Queue" پر کلک کریں۔','Process queue'=>'قطار پراسیس کریں','Process Pending Queue'=>'زیرِ التوا قطار پراسیس کریں','Immediately runs the AI pipeline on all pending queue items without waiting for WP-Cron. Use this to test the end-to-end flow after a poll.'=>'WP-Cron کا انتظار کیے بغیر فوراً تمام زیرِ التوا قطار آئٹمز پر AI پائپ لائن چلاتا ہے۔ پول کے بعد اینڈ ٹو اینڈ فلو جانچنے کے لیے اسے استعمال کریں۔','Force reprocess'=>'دوبارہ پراسیس پر مجبور کریں','Force Reprocess Inbox'=>'ان باکس دوبارہ پراسیس پر مجبور کریں','Resets failed/stuck/orphaned queue rows back to pending, then immediately polls for unprocessed messages. Then click "Process Pending Queue" to run the AI pipeline. Already-published artworks with valid posts are never re-processed.'=>'ناکام/پھنسے/یتیم قطار قطاروں کو واپس زیرِ التوا پر ری سیٹ کرتا ہے، پھر فوراً غیر پراسیس شدہ پیغامات کے لیے پول کرتا ہے۔ پھر AI پائپ لائن چلانے کے لیے "Process Pending Queue" پر کلک کریں۔ پہلے سے شائع شدہ اور درست پوسٹس والے آرٹ ورکس کبھی دوبارہ پراسیس نہیں ہوتے۔','Send Test'=>'ٹیسٹ بھیجیں','Deliverability'=>'ترسیلی صلاحیت','A diagnostic check only — nothing here changes how mail is sent. On ordinary hosting (PHP mail(), no SMTP plugin), mail sent from an address that doesn\'t match your site\'s own domain, or from a domain with no SPF/DMARC record at all, is increasingly likely to land in spam or be rejected outright by large mailbox providers. If any row below looks wrong, the most reliable fix is installing an SMTP-sending plugin (WP Mail SMTP, Post SMTP, FluentSMTP, and others all work) configured against a real transactional mail provider, and adding SPF/DMARC records for the domain you send from at your DNS host.'=>'یہ صرف ایک تشخیصی جانچ ہے — یہاں کچھ بھی میل بھیجنے کے طریقے کو نہیں بدلتا۔ عام ہوسٹنگ (PHP mail()، کوئی SMTP پلگ اِن نہیں) پر، ایسی پتے سے بھیجی گئی میل جو آپ کی سائٹ کے اپنے ڈومین سے میل نہ کھاتی ہو، یا ایسے ڈومین سے ہو جس کے پاس SPF/DMARC ریکارڈ ہی نہ ہو، بڑے میل باکس فراہم کنندگان کے ہاں اسپیم میں جانے یا سیدھا مسترد ہونے کے امکانات بڑھ جاتے ہیں۔ اگر نیچے کوئی قطار غلط لگتی ہے، تو سب سے قابلِ اعتماد حل ایک SMTP بھیجنے والا پلگ اِن (WP Mail SMTP، Post SMTP، FluentSMTP، اور دیگر بھی کام کرتے ہیں) نصب کرنا ہے، جسے ایک حقیقی ٹرانزیکشنل میل فراہم کنندہ کے ساتھ ترتیب دیا گیا ہو، اور جس ڈومین سے آپ بھیجتے ہیں اس کے لیے اپنے DNS ہوسٹ پر SPF/DMARC ریکارڈز شامل کرنا ہے۔','From identity'=>'بھیجنے والی شناخت','Domain matches site?'=>'کیا ڈومین سائٹ سے مطابقت رکھتا ہے؟','SPF record'=>'SPF ریکارڈ','DMARC record'=>'DMARC ریکارڈ','SMTP plugin'=>'SMTP پلگ اِن','Detected: %s'=>'پتہ چلا: %s','None of the common SMTP-sending plugins were detected — this site is likely relying on PHP\'s built-in mail(), which most hosts deliver poorly through.'=>'عام SMTP بھیجنے والے پلگ اِنز میں سے کوئی بھی معلوم نہیں ہوا — غالباً یہ سائٹ PHP کی بلٹ اِن mail() پر انحصار کر رہی ہے، جس کے ذریعے زیادہ تر ہوسٹس میل کو اچھے طریقے سے deliver نہیں کرتے۔','Send a real test email to:'=>'اس پتے پر ایک حقیقی ٹیسٹ ای میل بھیجیں:','Sends one plain-text email from the same community identity used for review/vote/vouch mail. Reaching your inbox is a good sign; landing in spam or not arriving at all confirms a real deliverability problem regardless of what the checks above say.'=>'اسی کمیونٹی شناخت سے ایک سادہ متن کی ای میل بھیجتا ہے جو review/vote/vouch میل کے لیے استعمال ہوتی ہے۔ اگر یہ آپ کے ان باکس میں پہنچ جائے تو یہ اچھی علامت ہے؛ اگر اسپیم میں چلی جائے یا بالکل نہ پہنچے تو اس سے قطع نظر کہ اوپر کے چیک کیا کہتے ہیں، ایک حقیقی ترسیلی مسئلہ ثابت ہوتا ہے۔','Found'=>'مل گیا','Not found'=>'نہیں ملا','DNS lookup failed'=>'DNS تلاش ناکام ہوگئی','Unavailable on this host'=>'اس ہوسٹ پر دستیاب نہیں','No address configured'=>'کوئی پتہ ترتیب نہیں دیا گیا','[TEST] Deliverability check from %s'=>'[TEST] %s سے ترسیلی صلاحیت کی جانچ','This is a one-off deliverability test from your Agnosis Settings → Email Inbox page. If you\'re reading this in your inbox (not spam), the community/transactional From identity is deliverable to this address.'=>'یہ آپ کے Agnosis Settings → Email Inbox صفحے سے ایک یک وقتی ترسیلی صلاحیت کا ٹیسٹ ہے۔ اگر آپ اسے اپنے ان باکس میں پڑھ رہے ہیں (اسپیم میں نہیں)، تو کمیونٹی/ٹرانزیکشنل From شناخت اس پتے تک پہنچنے کے قابل ہے۔','Pending Applications'=>'زیرِ التوا درخواستیں','%d application is awaiting email confirmation from the applicant and isn\'t listed below yet.'=>'%d درخواست کنندہ کی ای میل تصدیق کا منتظر ہے اور ابھی نیچے درج نہیں۔' . "\0" . '%d درخواستیں درخواست کنندگان کی ای میل تصدیق کے منتظر ہیں اور ابھی نیچے درج نہیں۔','No pending applications.'=>'کوئی زیرِ التوا درخواستیں نہیں۔','%d positive vote(s) currently required for admission.'=>'داخلے کے لیے فی الحال %d مثبت ووٹ درکار ہیں۔','Applicant'=>'درخواست دہندہ','Applied'=>'درخواست دی','Votes'=>'ووٹز','Bio / Portfolio'=>'سوانح / پورٹ فولیو','%1$d / %2$d'=>'%1$d / %2$d','Portfolio ↗'=>'پورٹ فولیو ↗','Admit'=>'داخل کریں','Reject'=>'مسترد کریں','No admitted members yet.'=>'ابھی تک کوئی قبول شدہ اراکین نہیں۔','Joined'=>'شامل ہوئے','Banned until %s'=>'%s تک ممنوع','Banned'=>'ممنوع','Active'=>'فعال','This address has bounced or been reported as spam — mail may no longer be reaching this artist.'=>'یہ پتہ واپس آ گیا ہے یا اسے اسپام کے طور پر رپورٹ کیا گیا ہے — ممکن ہے اب اس فنکار تک میل نہ پہنچ رہی ہو۔','⚠ %d bounce'=>'⚠ %d واپسی' . "\0" . '⚠ %d واپسیاں','This artist has muted community broadcast messages.'=>'اس فنکار نے کمیونٹی براڈکاسٹ پیغامات کو خاموش کر دیا ہے۔','🔇 Broadcasts muted'=>'🔇 براڈکاسٹس خاموش ہیں','This artist receives one daily digest of open applications instead of an email per application.'=>'یہ فنکار ہر درخواست کے لیے ایک ای میل کے بجائے کھلی درخواستوں کا ایک روزانہ خلاصہ وصول کرتا ہے۔','📬 Vote digest mode'=>'📬 ووٹ ڈائجسٹ موڈ','Leave the date blank to ban indefinitely. Continue?'=>'غیر معینہ مدت تک پابندی کے لیے تاریخ خالی چھوڑ دیں۔ جاری رکھیں؟','Leave blank to ban indefinitely'=>'غیر معینہ مدت تک پابندی کے لیے خالی چھوڑ دیں','Suspend'=>'معطل کریں','Permanently delete this artist and all their content? This cannot be undone.'=>'اس فنکار اور اس کا تمام مواد مستقل طور پر حذف کر دیا جائے؟ اسے واپس نہیں لایا جا سکتا۔','Open a community removal vote for this artist? All members will be emailed.'=>'اس فنکار کے لیے کمیونٹی ہٹانے کا ووٹ کھولا جائے؟ تمام اراکین کو ای میل بھیجی جائے گی۔','Open Vote'=>'ووٹ کھولیں','Newsletter Status'=>'نیوز لیٹر کی حالت','You have %1$d confirmed public subscribers, above the configured comfort threshold of %2$d. Self-hosted sending still works, but you may want to connect an email service provider (e.g. Brevo\'s free tier) for better deliverability at this size.'=>'آپ کے پاس %1$d تصدیق شدہ عوامی سبسکرائبرز ہیں، جو %2$d کی مقررہ آرام دہ حد سے زیادہ ہیں۔ خود میزبانی کے ذریعے بھیجنا اب بھی کام کرتا ہے، لیکن اس حجم پر بہتر ترسیل کے لیے آپ کسی ای میل سروس فراہم کنندہ (مثلاً Brevo کا مفت پلان) سے منسلک ہونا چاہیں گے۔','Audience'=>'سامعین','Last sent'=>'آخری بار بھیجا گیا','Action'=>'عمل','Failed recipients'=>'ناکام وصول کنندگان','Send a test'=>'ٹیسٹ بھیجیں','%1$d admitted (%2$d opted out)'=>'%1$d شامل کیے گئے (%2$d نے دستبرداری اختیار کی)','Sending…'=>'بھیجا جا رہا ہے…','Idle'=>'غیر فعال','Send Now'=>'ابھی بھیجیں','Public'=>'عوامی','%1$d confirmed, %2$d pending confirmation, %3$d unsubscribed, %4$d bounced'=>'%1$d تصدیق شدہ، %2$d تصدیق کے منتظر، %3$d نے رکنیت ختم کی، %4$d واپس آیا','By language: %s'=>'زبان کے لحاظ سے: %s','Add the "Newsletter Signup" block to any page to let visitors subscribe to the public newsletter. Artists are enrolled automatically and can unsubscribe from any issue with one click.'=>'عوامی نیوز لیٹر کی رکنیت لینے کے لیے کسی بھی صفحے پر "نیوز لیٹر سائن اپ" بلاک شامل کریں۔ فنکار خودکار طور پر شامل ہو جاتے ہیں اور کسی بھی شمارے سے ایک کلک میں رکنیت ختم کر سکتے ہیں۔','Never'=>'کبھی نہیں','Unknown'=>'نامعلوم','None'=>'کوئی نہیں','%d failed'=>'%d ناکام' . "\0" . '%d ناکام','Retry Failed'=>'ناکام کو دوبارہ آزمائیں','Invite an Artist'=>'ایک فنکار کو مدعو کریں','Send a one-off email inviting someone to apply. Nothing is tracked or scheduled — this sends immediately to the address below.'=>'کسی کو درخواست دینے کی دعوت دینے کے لیے ایک ایک بار کی ای میل بھیجیں۔ کچھ بھی ٹریک یا شیڈول نہیں کیا جاتا — یہ نیچے دیے گئے پتے پر فوراً بھیجا جاتا ہے۔','artist@example.com'=>'artist@example.com','Send Invitation'=>'دعوت بھیجیں','Permission denied.'=>'اجازت نہیں دی گئی۔','OpenAI API key not configured.'=>'OpenAI API کلید ترتیب نہیں دی گئی۔','OpenAI connection successful.'=>'OpenAI کنکشن کامیاب رہا۔','Anthropic API key not configured.'=>'Anthropic API کلید ترتیب نہیں دی گئی۔','Anthropic connection successful.'=>'Anthropic کنکشن کامیاب رہا۔','WordPress AI Client requires WordPress 7.0 or later.'=>'WordPress AI Client کے لیے WordPress 7.0 یا اس کے بعد کا ورژن درکار ہے۔','No text-generation model configured. Set one up under Settings → Connectors.'=>'کوئی ٹیکسٹ جنریشن ماڈل ترتیب نہیں دیا گیا۔ سیٹنگز → کنیکٹرز میں جا کر ایک سیٹ کریں۔','WordPress AI Client is available and a text-generation model is configured.'=>'WordPress AI Client دستیاب ہے اور ایک ٹیکسٹ جنریشن ماڈل ترتیب دیا گیا ہے۔','Unknown provider.'=>'نامعلوم فراہم کنندہ۔','HTTP %d'=>'HTTP %d','The artist sent no subject line or message with this submission — let the image speak entirely for itself.'=>'اس پیشکش کے ساتھ فنکار نے کوئی موضوعی سطر یا پیغام نہیں بھیجا — تصویر کو خود اپنی بات کہنے دیں۔','Name'=>'نام','Bio'=>'حالاتِ زندگی','Statement'=>'بیان','%1$s must be %2$d characters or fewer.'=>'%1$s %2$d حروف یا اس سے کم ہونا چاہیے۔','Please select your language.'=>'براہِ کرم اپنی زبان منتخب کریں۔','An account with this email address already exists.'=>'اس ای میل پتے کے ساتھ ایک اکاؤنٹ پہلے ہی موجود ہے۔','This email address belongs to an admitted artist.'=>'یہ ای میل پتہ ایک منظور شدہ فنکار سے متعلق ہے۔','An application for this email address is already pending.'=>'اس ای میل پتے کے لیے ایک درخواست پہلے ہی زیرِ التوا ہے۔','Application not found.'=>'درخواست نہیں ملی۔','Only admitted artists can vouch.'=>'صرف منظور شدہ فنکار ہی توثیق کر سکتے ہیں۔','Admin access required.'=>'ایڈمن رسائی درکار ہے۔','You cannot vote on your own application.'=>'آپ اپنی ہی درخواست پر ووٹ نہیں دے سکتے۔','Invalid or incomplete link.'=>'غلط یا نامکمل لنک۔','This confirmation link is invalid or has already been used.'=>'یہ تصدیقی لنک غلط ہے یا پہلے ہی استعمال ہو چکا ہے۔','Confirm your application?'=>'اپنی درخواست کی تصدیق کریں؟','Your application will open for community review once you confirm below.'=>'نیچے تصدیق کرنے کے بعد آپ کی درخواست کمیونٹی کے جائزے کے لیے کھل جائے گی۔','Confirm my application'=>'میری درخواست کی تصدیق کریں','This community is currently full, so your application has joined the waitlist — when a member leaves, the next person in line is welcomed in.'=>'یہ کمیونٹی فی الحال مکمل ہے، اس لیے آپ کی درخواست انتظار کی فہرست میں شامل کر دی گئی ہے — جب کوئی رکن نکلتا ہے، تو قطار میں اگلے فرد کا خیرمقدم کیا جاتا ہے۔','You\'re all set — the community can now review your application and vote.'=>'آپ کا کام مکمل ہے — اب کمیونٹی آپ کی درخواست کا جائزہ لے سکتی ہے اور ووٹ دے سکتی ہے۔','Application confirmed'=>'درخواست کی تصدیق ہو گئی','Thanks, %s!'=>'شکریہ، %s!','Link error'=>'لنک میں خرابی','Confirm your application to %s'=>'اپنی %s درخواست کی تصدیق کریں','Your application to %s'=>'آپ کی %s درخواست','Application by %s has closed'=>'%s کی درخواست بند ہو گئی ہے','Welcome to %s'=>'%s میں خوش آمدید','We received your application to %s'=>'ہم نے %s کے لیے آپ کی درخواست موصول کر لی ہے','Hi %s,'=>'سلام %s،','One last step before %s can review your application: confirm this is really your email address.'=>'%s آپ کی درخواست کا جائزہ لے سکے، اس سے پہلے آخری مرحلہ: تصدیق کریں کہ یہ واقعی آپ کا ای میل پتہ ہے۔','If you didn\'t apply, simply ignore this email — nothing happens until this link is clicked.'=>'اگر آپ نے درخواست نہیں دی تو بس اس ای میل کو نظر انداز کر دیں — جب تک اس لنک پر کلک نہیں کیا جاتا کچھ نہیں ہوگا۔','Thank you for applying to %s. Your application has been received and is now open for community review.'=>'%s کے لیے درخواست دینے کا شکریہ۔ آپ کی درخواست موصول ہو گئی ہے اور اب کمیونٹی کے جائزے کے لیے کھلی ہے۔','The community has %d days to vote. We will let you know the outcome by email.'=>'کمیونٹی کے پاس ووٹ دینے کے لیے %d دن ہیں۔ ہم نتیجے سے آپ کو ای میل کے ذریعے آگاہ کریں گے۔','New application: %1$s wants to join %2$s'=>'نئی درخواست: %1$s %2$s میں شامل ہونا چاہتا/چاہتی ہے','%1$s has applied to join %2$s. You have %3$d days to vote.'=>'%1$s نے %2$s میں شامل ہونے کے لیے درخواست دی ہے۔ آپ کے پاس ووٹ دینے کے لیے %3$d دن ہیں۔','Portfolio:'=>'پورٹ فولیو:','Vote YES'=>'ہاں کو ووٹ دیں','Vote NO'=>'نہیں کو ووٹ دیں','You can change your vote at any time within the voting window.'=>'آپ ووٹنگ کے دوران کسی بھی وقت اپنا ووٹ تبدیل کر سکتے ہیں۔','Thank you for applying to %s. Unfortunately, your application did not receive enough votes within the voting window.'=>'%s کے لیے درخواست دینے کا شکریہ۔ بدقسمتی سے، آپ کی درخواست کو ووٹنگ کے دوران کافی ووٹ نہیں مل سکے۔','You are welcome to apply again in the future.'=>'آپ مستقبل میں دوبارہ درخواست دے سکتے ہیں۔','The application by %s has closed without reaching the admission threshold. No action required.'=>'%s کی درخواست بغیر داخلہ حد تک پہنچے بند ہو گئی ہے۔ کسی کارروائی کی ضرورت نہیں۔','The %s community has admitted you as an artist. Welcome!'=>'%s کمیونٹی نے آپ کو فنکار کے طور پر قبول کر لیا ہے۔ خوش آمدید!','Your gallery:'=>'آپ کی گیلری:','Your submissions:'=>'آپ کی پیشکشیں:','How to share your work — send an email to:'=>'اپنا کام شیئر کرنے کا طریقہ — اس ای میل پر بھیجیں:','Subject line conventions:'=>'موضوعی سطر کے قواعد:','Artwork (default) — any subject'=>'آرٹ ورک (ڈیفالٹ) — کوئی بھی موضوع','[Biography] — biography update'=>'[سوانح] — سوانحی تازہ کاری','[Event] — event announcement'=>'[تقریب] — تقریب کا اعلان','[Photo] — publish as-is, no AI enhancement (fallback for mail apps without To: aliases)'=>'[تصویر] — جوں کا توں شائع کریں، کوئی AI بہتری نہیں (ایسے میل ایپس کے لیے متبادل جن میں To: aliases نہ ہوں)','[Pure] — publish exactly as sent, no AI at all (fallback for mail apps without To: aliases)'=>'[خالص] — جوں کا توں بالکل ویسا ہی شائع کریں، کوئی AI بالکل نہیں (ایسے میل ایپس کے لیے متبادل جن میں To: aliases نہ ہوں)','To leave the network and delete your account:'=>'نیٹ ورک چھوڑنے اور اپنا اکاؤنٹ حذف کرنے کے لیے:','Send any email (no attachment needed). You will receive a confirmation link — nothing is deleted until you click it.'=>'کوئی بھی ای میل بھیجیں (اٹیچمنٹ کی ضرورت نہیں)۔ آپ کو ایک تصدیقی لنک موصول ہوگا — جب تک آپ اس پر کلک نہیں کرتے کچھ حذف نہیں کیا جاتا۔','No login is needed to work with Agnosis — everything above happens by email. If you\'d also like to use the site\'s optional online features (like previewing a submission before it publishes), you can set up a password whenever you like using'=>'Agnosis کے ساتھ کام کرنے کے لیے لاگ اِن کی ضرورت نہیں — اوپر سب کچھ ای میل کے ذریعے ہوتا ہے۔ اگر آپ سائٹ کی اختیاری آن لائن خصوصیات بھی استعمال کرنا چاہیں (مثلاً شائع ہونے سے پہلے کسی جمع کرائی گئی چیز کا پیش منظر دیکھنا)، تو آپ جب چاہیں ایک پاس ورڈ سیٹ کر سکتے ہیں','password recovery'=>'پاس ورڈ کی بازیافت','Submit artwork'=>'آرٹ ورک جمع کرائیں','Submit biography'=>'سوانح جمع کرائیں','Submit event'=>'تقریب جمع کرائیں','Replace artwork (subject: exact title)'=>'آرٹ ورک تبدیل کریں (موضوع: درست عنوان)','Remove artwork (subject: exact title)'=>'آرٹ ورک حذف کریں (موضوع: درست عنوان)','Feature artwork in the shared gallery (subject: exact title)'=>'مشترکہ گیلری میں آرٹ ورک نمایاں کریں (موضوع: درست عنوان)','Photo-only — publish as-is, no AI enhancement'=>'صرف تصویر — جوں کا توں شائع کریں، کوئی AI بہتری نہیں','Pure — publish exactly as sent, no AI at all'=>'خالص — جوں کا توں بالکل ویسا ہی شائع کریں، کوئی AI بالکل نہیں','About %s'=>'%s کے بارے میں','%1$s — %2$s'=>'%1$s — %2$s','[%s] Your community message was not sent — too long'=>'[%s] آپ کا کمیونٹی پیغام نہیں بھیجا گیا — بہت طویل','[%s] Your community message was not sent — no content found'=>'[%s] آپ کا کمیونٹی پیغام نہیں بھیجا گیا — کوئی مواد نہیں ملا','[%1$s] Community message from %2$s'=>'[%1$s] %2$s کی طرف سے کمیونٹی پیغام','%1$s <%2$s> sent a message to the community:'=>'%1$s <%2$s> نے کمیونٹی کو ایک پیغام بھیجا ہے:','Subject: %s'=>'موضوع: %s','Hit reply to respond — your reply goes back to the whole community, translated automatically, just like this message.'=>'جواب دینے کے لیے ریپلائی کریں — آپ کا جواب پوری کمیونٹی کو واپس جائے گا، خودکار طور پر ترجمہ ہو کر، بالکل اسی پیغام کی طرح۔','This message was sent by %s.'=>'یہ پیغام %s نے بھیجا ہے۔','%1$s via %2$s'=>'%1$s بذریعہ %2$s','no limit'=>'کوئی حد نہیں','Community size-cap vote open at %s'=>'%s پر کمیونٹی سائز-کیپ ووٹ کھلا ہے','Community size cap changed at %s'=>'%s پر کمیونٹی سائز کیپ تبدیل ہوگئی','The community voted to change the membership size cap to %1$s (proposal #%2$d). The new cap is now in effect.'=>'کمیونٹی نے رکنیت کی زیادہ سے زیادہ حد %1$s کرنے کے لیے ووٹ دیا (تجویز #%2$d)۔ نئی حد اب نافذ ہے۔','Community size-cap proposal did not pass at %s'=>'%s پر کمیونٹی سائز-کیپ کی تجویز منظور نہیں ہوئی','Only community members can do this.'=>'یہ صرف کمیونٹی کے اراکین کر سکتے ہیں۔','The cap must be zero or a positive number.'=>'حد صفر یا مثبت عدد ہونی چاہیے۔','That is already the current cap.'=>'یہ پہلے ہی موجودہ حد ہے۔','A different cap proposal is already under way. Resolve or co-sign that one first.'=>'ایک مختلف حد کی تجویز پہلے ہی زیرِ عمل ہے۔ پہلے اسے حل کریں یا اس کی تائید کریں۔','No active proposal to co-sign.'=>'تائید کے لیے کوئی فعال تجویز نہیں۔','Proposal not found.'=>'تجویز نہیں ملی۔','This vote is not currently open.'=>'یہ ووٹ فی الحال کھلا نہیں ہے۔','This artist can\'t be reached through this form right now.'=>'اس فنکار سے اس وقت اس فارم کے ذریعے رابطہ نہیں کیا جا سکتا۔','Thanks — your message has been sent.'=>'شکریہ — آپ کا پیغام بھیج دیا گیا ہے۔','Spam, scams, or unsolicited commercial advertising unrelated to genuinely contacting the artist about their work'=>'اسپام، دھوکہ دہی، یا غیر مطلوب تجارتی اشتہارات جو فنکار سے اس کے کام کے بارے میں حقیقی طور پر رابطہ کرنے سے غیر متعلق ہوں','Flagged by automatic content review.'=>'خودکار مواد کے جائزے کے ذریعے نشان زد کیا گیا۔','New message from %s via your Agnosis contact form'=>'آپ کے Agnosis رابطہ فارم کے ذریعے %s سے نیا پیغام','From: %s'=>'بذریعہ: %s','(no name provided)'=>'(کوئی نام فراہم نہیں کیا گیا)','Original message, as submitted:'=>'اصل پیغام، جیسا جمع کروایا گیا:','Your name (optional)'=>'آپ کا نام (اختیاری)','Your email address'=>'آپ کا ای میل پتہ','you@example.com'=>'you@example.com','Send message'=>'پیغام بھیجیں','Thanks — your message has been sent. You can reach out to this artist again a little later.'=>'شکریہ — آپ کا پیغام بھیج دیا گیا ہے۔ آپ تھوڑی دیر بعد اس فنکار سے دوبارہ رابطہ کر سکتے ہیں۔','Something went wrong. Please try again.'=>'کچھ غلط ہو گیا۔ براہِ کرم دوبارہ کوشش کریں۔','Authentication required.'=>'تصدیق درکار ہے۔','This field cannot be edited here.'=>'اس فیلڈ میں یہاں ترمیم نہیں کی جا سکتی۔','That date could not be understood.'=>'اس تاریخ کو سمجھا نہیں جا سکا۔','That does not look like a valid timezone (e.g. "Europe/Madrid").'=>'یہ درست ٹائم زون نہیں لگتا (مثلاً "Europe/Madrid").','That does not look like a valid link (must start with http:// or https://).'=>'یہ درست لنک نہیں لگتا (http:// یا https:// سے شروع ہونا چاہیے)۔','The title cannot be empty.'=>'عنوان خالی نہیں ہو سکتا۔','Saved — translations will update within a few minutes.'=>'محفوظ کر دیا گیا — تراجم چند منٹوں میں اپ ڈیٹ ہو جائیں گے۔','No image file was received.'=>'کوئی تصویر فائل موصول نہیں ہوئی۔','Please upload a JPEG, PNG, WebP, or GIF image.'=>'براہِ کرم JPEG، PNG، WebP، یا GIF تصویر اپ لوڈ کریں۔','The uploaded file could not be read.'=>'اپ لوڈ کی گئی فائل پڑھی نہیں جا سکی۔','Untitled'=>'بغیر عنوان','Photo replaced — the original is kept and can be restored later.'=>'تصویر بدل دی گئی — اصل محفوظ ہے اور بعد میں بحال کی جا سکتی ہے۔','There is no photo to restore.'=>'بحال کرنے کے لیے کوئی تصویر موجود نہیں۔','No earlier version of this photo was found.'=>'اس تصویر کا کوئی پچھلا ورژن نہیں ملا۔','Restored the earlier photo.'=>'پچھلی تصویر بحال کر دی گئی۔','Only admitted artists may edit their own content.'=>'صرف منظور شدہ فنکار اپنی مواد میں خود ترمیم کر سکتے ہیں۔','Content not found.'=>'مواد نہیں ملا۔','Only published content can be corrected here.'=>'یہاں صرف شائع شدہ مواد کی تصحیح کی جا سکتی ہے۔','You may only edit your own content.'=>'آپ صرف اپنے مواد میں ترمیم کر سکتے ہیں۔','This page is not in your own language. Edit the version in your language instead.'=>'یہ صفحہ آپ کی اپنی زبان میں نہیں ہے۔ اس کے بجائے اپنی زبان والے ورژن میں ترمیم کریں۔','Unsupported field target.'=>'غیر معاون فیلڈ ہدف۔','Save'=>'محفوظ کریں','Cancel'=>'منسوخ','Saving…'=>'محفوظ کیا جا رہا ہے…','Replace photo'=>'تصویر بدلیں','Uploading…'=>'اپ لوڈ کیا جا رہا ہے…','Restore earlier photo'=>'پہلی تصویر بحال کریں','Restoring…'=>'بحال کیا جا رہا ہے…','You have left'=>'آپ چلے گئے ہیں','Your account and everything you published on %s have been permanently deleted. Nothing tied to you is stored here anymore.'=>'آپ کا اکاؤنٹ اور %s پر آپ کی شائع کردہ ہر چیز مستقل طور پر حذف کر دی گئی ہے۔ آپ سے متعلق کچھ بھی اب یہاں محفوظ نہیں ہے۔','Link expired or already used'=>'لنک کی مدت ختم ہو چکی ہے یا پہلے ہی استعمال ہو چکا ہے','This confirmation link has already been used or is no longer valid. If you still want to leave, please request removal again from your account.'=>'یہ تصدیقی لنک پہلے ہی استعمال ہو چکا ہے یا اب درست نہیں رہا۔ اگر آپ پھر بھی جانا چاہتے ہیں تو براہِ کرم اپنے اکاؤنٹ سے دوبارہ حذف کرنے کی درخواست کریں۔','You must be logged in.'=>'آپ کو لاگ اِن ہونا ضروری ہے۔','Artist access required.'=>'فنکار کی رسائی درکار ہے۔','No active membership found for this account.'=>'اس اکاؤنٹ کے لیے کوئی فعال رکنیت نہیں ملی۔','You cannot nominate yourself for removal.'=>'آپ خود کو حذف کرنے کے لیے نامزد نہیں کر سکتے۔','Artist not found.'=>'فنکار نہیں ملا۔','Removal request not found.'=>'حذف کرنے کی درخواست نہیں ملی۔','You cannot vote on your own removal.'=>'آپ اپنی ہی حذف کرنے کی درخواست پر ووٹ نہیں دے سکتے۔','Confirm your departure from %s'=>'%s سے آپ کی روانگی کی تصدیق کریں','An artist has left %s'=>'ایک فنکار نے %s چھوڑ دیا ہے','You\'ve left %s'=>'آپ نے %s چھوڑ دیا ہے','Your membership at %s has been suspended'=>'%s پر آپ کی رکنیت معطل کر دی گئی ہے','Your membership at %s has been reinstated'=>'%s پر آپ کی رکنیت بحال کر دی گئی ہے','Community removal vote open at %s'=>'%s پر کمیونٹی ہٹانے کا ووٹ کھل گیا ہے','Community removal vote passed at %s'=>'%s پر کمیونٹی ہٹانے کا ووٹ منظور ہو گیا','Community removal vote did not pass at %s'=>'%s پر کمیونٹی ہٹانے کا ووٹ منظور نہیں ہو سکا','Please enter a valid email address.'=>'براہِ کرم درست ای میل ایڈریس درج کریں۔','wp_mail() reported a failure — check your site\'s outgoing mail configuration.'=>'wp_mail() نے ناکامی رپورٹ کی — اپنے سائٹ کے آؤٹ گوئنگ میل کنفیگریشن کو چیک کریں۔','You\'re invited to join %s'=>'آپ کو %s میں شامل ہونے کی دعوت دی جاتی ہے','[TEST] %s'=>'[TEST] %s','You\'re invited'=>'آپ کو دعوت دی جاتی ہے','Apply to join'=>'شامل ہونے کے لیے درخواست دیں','No account needed to apply — the community reviews and votes on every application.'=>'درخواست دینے کے لیے اکاؤنٹ کی ضرورت نہیں — کمیونٹی ہر درخواست کا جائزہ لیتی ہے اور اس پر ووٹ دیتی ہے۔','You are already an admitted Agnosis artist.'=>'آپ پہلے ہی ایک منظور شدہ Agnosis فنکار ہیں۔','Your name'=>'آپ کا نام','required'=>'لازمی','Email address'=>'ای میل ایڈریس','Short bio'=>'مختصر تعارف','A few sentences about your practice, medium, and background.'=>'اپنی مشق، میڈیم، اور پس منظر کے بارے میں چند جملے۔','Portfolio URL'=>'پورٹ فولیو URL','Why do you want to join?'=>'آپ شامل ہونا کیوں چاہتے ہیں؟','Language you work in'=>'وہ زبان جس میں آپ کام کرتے ہیں','Select your language'=>'اپنی زبان منتخب کریں','Helps us communicate and translate content in your language.'=>'ہمیں آپ کی زبان میں رابطہ کرنے اور مواد کا ترجمہ کرنے میں مدد ملتی ہے۔','Apply'=>'درخواست جمع کریں','Almost there — check your inbox for a confirmation email and click the link to open your application for community review.'=>'بس کچھ ہی باقی ہے — اپنی انباکس میں تصدیقی ای میل چیک کریں اور لنک پر کلک کر کے اپنی درخواست کو کمیونٹی کے جائزے کے لیے کھولیں۔','Please fill in all required fields.'=>'براہِ کرم تمام لازمی خانے پُر کریں۔','This preferences link is invalid or has been tampered with.'=>'یہ ترجیحات کا لنک غیر معتبر ہے یا اس میں چھیڑ چھاڑ کی گئی ہے۔','This preferences link is no longer valid for this account.'=>'یہ ترجیحات کا لنک اب اس اکاؤنٹ کے لیے درست نہیں ہے۔','Notification preferences'=>'اطلاعات کی ترجیحات','Mute community broadcast messages from other artists.'=>'دیگر فنکاروں کی کمیونٹی براڈکاسٹ پیغامات خاموش کریں۔','Application vote emails'=>'درخواست ووٹ ای میلز','Instantly, one email per application (default).'=>'فوراً، ہر درخواست کے لیے ایک ای میل (طے شدہ)۔','Once a day, a single digest of every application still awaiting my vote.'=>'دن میں ایک بار، میری ووٹ کی منتظر ہر درخواست کا ایک واحد خلاصہ۔','Turn off the contact form on my page — visitors won\'t be able to message me.'=>'اپنے صفحے پر رابطہ فارم بند کر دیں — زائرین آپ کو پیغام نہیں بھیج سکیں گے۔','Save preferences'=>'ترجیحات محفوظ کریں','Community broadcasts are now muted.'=>'کمیونٹی براڈکاسٹ اب خاموش کر دیے گئے ہیں۔','You\'ll continue to receive community broadcasts.'=>'آپ کو کمیونٹی براڈکاسٹ ملتے رہیں گے۔','You\'ll receive one daily digest of applications awaiting your vote.'=>'آپ کو اپنی ووٹ کے منتظر درخواستوں کا روزانہ ایک خلاصہ ملے گا۔','You\'ll receive an email as soon as each new application arrives.'=>'جیسے ہی ہر نئی درخواست آئے گی، آپ کو ایک ای میل موصول ہوگی۔','The contact form on your page is now turned off.'=>'آپ کے صفحے پر رابطہ فارم اب بند کر دیا گیا ہے۔','Visitors can still reach you through the contact form on your page.'=>'زائرین اب بھی آپ کے صفحے پر رابطہ فارم کے ذریعے آپ سے رابطہ کر سکتے ہیں۔','Preferences saved'=>'ترجیحات محفوظ ہو گئیں','Artworks'=>'فن پارے','Write about this artwork…'=>'اس فن پارے کے بارے میں لکھیں…','Biographies'=>'سوانح حیاتیں','Biography'=>'سوانح حیات','Add New Biography'=>'نئی سوانح حیات شامل کریں','Edit Biography'=>'سوانح حیات میں ترمیم کریں','New Biography'=>'نئی سوانح حیات','View Biography'=>'سوانح حیات دیکھیں','Search Biographies'=>'سوانح حیات تلاش کریں','No biographies found.'=>'کوئی سوانح حیات نہیں ملی۔','No biographies in trash.'=>'ردّی میں کوئی سوانح حیات نہیں ہے۔','All Biographies'=>'تمام سوانح حیات','Events'=>'تقریبات','Event'=>'تقریب','Add New Event'=>'نئی تقریب شامل کریں','Edit Event'=>'تقریب میں ترمیم کریں','New Event'=>'نئی تقریب','View Event'=>'تقریب دیکھیں','Search Events'=>'تقریبات تلاش کریں','No events found.'=>'کوئی تقریبات نہیں ملیں۔','No events in trash.'=>'ردّی میں کوئی تقریبات نہیں ہیں۔','All Events'=>'تمام تقریبات','Medium'=>'میڈیم','Mediums'=>'میڈیمز','Search Mediums'=>'میڈیمز تلاش کریں','All Mediums'=>'تمام میڈیمز','Edit Medium'=>'میڈیم میں ترمیم کریں','Update Medium'=>'میڈیم اپ ڈیٹ کریں','Add New Medium'=>'نیا میڈیم شامل کریں','New Medium Name'=>'نئے میڈیم کا نام','Sensitive by default'=>'Sensitive by default','Mark artworks under this medium as sensitive content by default'=>'Mark artworks under this medium as sensitive content by default','Federated posts under this medium will carry a content warning on the Fediverse (e.g. Mastodon) unless the artist turns it off for a specific piece.'=>'Federated posts under this medium will carry a content warning on the Fediverse (e.g. Mastodon) unless the artist turns it off for a specific piece.','Artwork'=>'فن پارہ','Add New'=>'نیا شامل کریں','Add New Artwork'=>'نیا فن پارہ شامل کریں','Edit Artwork'=>'فن پارے میں ترمیم کریں','New Artwork'=>'نیا فن پارہ','View Artwork'=>'فن پارہ دیکھیں','Search Artworks'=>'فن پارے تلاش کریں','No artworks found.'=>'کوئی فن پارے نہیں ملے۔','No artworks in trash.'=>'ردّی میں کوئی فن پارے نہیں ہیں۔','All Artworks'=>'تمام فن پارے','Artwork Archives'=>'فن پاروں کے آرکائیوز','Artwork Attributes'=>'فن پارے کی خصوصیات','Invalid vote link.'=>'غلط ووٹ لنک۔','This vote link is invalid or has been tampered with.'=>'یہ ووٹ لنک غلط ہے یا اس میں چھیڑ چھاڑ کی گئی ہے۔','Voter account not found.'=>'ووٹ دینے والا اکاؤنٹ نہیں ملا۔','Vote to remove this artist from the community?'=>'کیا اس فنکار کو کمیونٹی سے ہٹانے کے لیے ووٹ دیں؟','Vote to keep this artist in the community?'=>'کیا اس فنکار کو کمیونٹی میں برقرار رکھنے کے لیے ووٹ دیں؟','Your vote will be recorded once you confirm below.'=>'آپ کا ووٹ نیچے تصدیق کرنے کے بعد ریکارڈ کر لیا جائے گا۔','Confirm my vote'=>'میرا ووٹ تصدیق کریں','You voted to remove this artist from the community.'=>'آپ نے اس فنکار کو کمیونٹی سے ہٹانے کے لیے ووٹ دیا۔','You voted to keep this artist in the community.'=>'آپ نے اس فنکار کو کمیونٹی میں برقرار رکھنے کے لیے ووٹ دیا۔','%d vote to remove recorded so far.'=>'اب تک ہٹانے کے لیے %d ووٹ ریکارڈ ہو چکے ہیں۔' . "\0" . 'اب تک ہٹانے کے لیے %d ووٹ ریکارڈ ہو چکے ہیں۔','Vote recorded'=>'ووٹ ریکارڈ ہو گیا','Vote error'=>'ووٹ میں خرابی','%d application awaiting your vote'=>'آپ کے ووٹ کے منتظر %d درخواست' . "\0" . 'آپ کے ووٹ کے منتظر %d درخواستیں','Here\'s your daily digest of applications to %1$s still awaiting your vote. Each has a %2$d-day voting window from when it was confirmed.'=>'یہ %1$s کے لیے درخواستوں کا آپ کا روزانہ خلاصہ ہے جو اب بھی آپ کے ووٹ کی منتظر ہیں۔ ہر ایک کے لیے تصدیق کے وقت سے %2$d دن کی ووٹنگ مدت ہے۔','Prefer these one at a time again? You can switch back any time from your notification preferences link below.'=>'کیا ترجیح ہے کہ یہ ایک ایک کر کے دوبارہ آئیں؟ آپ نیچے دیے گئے نوٹیفکیشن ترجیحات کے لنک سے کسی بھی وقت واپس بدل سکتے ہیں۔','Vote in favor of this application?'=>'اس درخواست کے حق میں ووٹ دیں؟','Vote against this application?'=>'اس درخواست کے خلاف ووٹ دیں؟','You voted in favor of this application.'=>'آپ نے اس درخواست کے حق میں ووٹ دیا۔','You voted against this application.'=>'آپ نے اس درخواست کے خلاف ووٹ دیا۔','%d positive vote recorded so far.'=>'اب تک %d مثبت ووٹ ریکارڈ ہو چکے ہیں۔' . "\0" . 'اب تک %d مثبت ووٹ ریکارڈ ہو چکے ہیں۔','is active and configured for'=>'فعال ہے اور اس کے لیے ترتیب دیا گیا ہے','Subdomain'=>'ذیلی ڈومین','routing mode'=>'روٹنگ موڈ','This conflicts with Agnosis artist subdomains — both plugins would claim the same subdomain namespace.'=>'یہ Agnosis کے فنکار ذیلی ڈومینز سے ٹکراتا ہے — دونوں پلگ اِن ایک ہی ذیلی ڈومین نامی جگہ کا دعویٰ کریں گے۔','Artist subdomain routing is'=>'فنکار ذیلی ڈومین روٹنگ','completely inactive'=>'مکمل طور پر غیر فعال ہے','until this is resolved.'=>'جب تک یہ حل نہ ہو جائے۔','Fix: open'=>'درست کریں: کھولیں','Settings'=>'ترتیبات','Language Router'=>'Language Router','and switch the URL strategy to'=>'اور URL حکمتِ عملی کو تبدیل کریں','Path prefix (subfolder)'=>'پاتھ پریفکس (سب فولڈر)','This is the LinguaForge default and allows artist subdomains to coexist with language subfolders'=>'یہ LinguaForge کی ڈیفالٹ ہے اور فنکار ذیلی ڈومینز کو زبان کے سب فولڈرز کے ساتھ ساتھ موجود رہنے کی اجازت دیتی ہے','Agnosis — Artist Subdomain Routing is disabled'=>'Agnosis — Artist Subdomain Routing غیر فعال ہے','Open LinguaForge Settings'=>'LinguaForge ترتیبات کھولیں','Agnosis Artist'=>'Agnosis فنکار','My Submissions'=>'میری گذارشات','Join'=>'شامل ہوں','Send new artwork to be published.'=>'شائع کرنے کے لیے نیا فن پارہ بھیجیں۔','Update your artist biography.'=>'اپنی فنکارانہ سوانحِ حیات اپ ڈیٹ کریں۔','Announce an upcoming event.'=>'آنے والے ایونٹ کا اعلان کریں۔','Replace'=>'تبدیل کریں','Send a new version of an existing artwork — subject must match its title.'=>'موجودہ فن پارے کا نیا ورژن بھیجیں — سبجیکٹ اس کے عنوان سے مماثل ہونا چاہیے۔','Request an existing artwork or event be taken down — subject must match its title.'=>'موجودہ فن پارے یا ایونٹ کو ہٹانے کی درخواست کریں — سبجیکٹ اس کے عنوان سے مماثل ہونا چاہیے۔','Promote'=>'ترقی دیں','Choose which artwork represents you in the shared community gallery on the main site — subject must match its title. Your own subdomain already shows everything you\'ve published.'=>'منتخب کریں کہ مشترکہ کمیونٹی گیلری میں مرکزی سائٹ پر آپ کی نمائندگی کون سا فن پارہ کرے — سبجیکٹ اس کے عنوان سے مماثل ہونا چاہیے۔ آپ کا اپنا ذیلی ڈومین پہلے ہی وہ سب کچھ دکھاتا ہے جو آپ نے شائع کیا ہے۔','Photo-only'=>'صرف تصویر','Publish a photo exactly as sent — no AI enhancement, no quality check.'=>'تصویر کو بالکل اسی طرح شائع کریں جیسا بھیجی گئی ہے — نہ AI بہتری، نہ معیار کی جانچ۔','Pure'=>'خالص','Publish exactly as sent — no AI at all, not even the title/description pass.'=>'بالکل اسی طرح شائع کریں جیسا بھیجا گیا ہے — بالکل بھی AI نہیں، حتیٰ کہ عنوان/تفصیل کی پروسیسنگ بھی نہیں۔','Send a message to every other artist in the community.'=>'کمیونٹی کے ہر دوسرے فنکار کو ایک پیغام بھیجیں۔','Spotted something to fix after publishing? Log in and look for the pencil icon on your published page — you can correct the title, text, or photo yourself, no need to email us again.'=>'شائع کرنے کے بعد کچھ درست کرنا رہ گیا؟ لاگ اِن کریں اور اپنی شائع شدہ صفحے پر پنسل کے آئیکن کو تلاش کریں — آپ عنوان، متن یا تصویر خود درست کر سکتے ہیں، ہمیں دوبارہ ای میل کرنے کی ضرورت نہیں۔','Manage notification preferences: %s'=>'نوٹیفکیشن ترجیحات کا انتظام کریں: %s','Manage notification preferences'=>'نوٹیفکیشن ترجیحات کا انتظام کریں','%s — art blooming out of oblivion'=>'%s — فراموشی سے ابھرتا ہوا فن','Agnosis Membership Application'=>'ایگنوسِس رکنیت کی درخواست','Agnosis Governance Participation'=>'ایگنوسِس حکمرانی میں شرکت','Agnosis Newsletter Subscription'=>'ایگنوسِس نیوز لیٹر کی رکنیت','Agnosis Newsletter Delivery History'=>'ایگنوسِس نیوز لیٹر کی ترسیل کی تاریخ','Agnosis Contact Messages Sent'=>'ایگنوسِس رابطہ پیغامات بھیجے گئے','Agnosis Transactions'=>'ایگنوسِس لین دین','Agnosis Notification Preferences'=>'ایگنوسِس اطلاع کی ترجیحات','Display name'=>'ظاہری نام','Application statement'=>'درخواست کا بیان','Language'=>'زبان','Applied at'=>'درخواست دی گئی','Resolved at'=>'حل کیا گیا','Type'=>'قسم','Community vouch given'=>'کمیونٹی واؤچ دیا گیا','Date'=>'تاریخ','Admission vouch given'=>'داخلے کا واؤچ دیا گیا','Community removal vote'=>'کمیونٹی اخراج ووٹ','Vote'=>'ووٹ','Community size-cap vote'=>'کمیونٹی سائز کی حد کا ووٹ','Locale'=>'لوکیل','Subscribed at'=>'سبسکرائب کیا گیا','Confirmed at'=>'تصدیق کی گئی','Unsubscribed at'=>'ان سبسکرائب کیا گیا','Issue'=>'مسئلہ','Recipient type'=>'وصول کنندہ کی قسم','Queued at'=>'قطار میں شامل کیا گیا','Sent to artist'=>'فنکار کو بھیجا گیا','Translated message'=>'ترجمہ شدہ پیغام','Rejection reason'=>'رد کرنے کی وجہ','IP address'=>'آئی پی پتہ','Sent at'=>'بھیجا گیا','Amount'=>'رقم','Currency'=>'کرنسی','Fee'=>'فیس','Gateway'=>'گیٹ وے','Your membership application/account is still active. To remove this data, use the "leave the network" link from any Agnosis email, or ask an administrator.'=>'آپ کی رکنیت کی درخواست/اکاؤنٹ ابھی فعال ہے۔ یہ ڈیٹا ہٹانے کے لیے، کسی بھی ایگنوسِس ای میل میں موجود "نیٹ ورک چھوڑیں" لنک استعمال کریں، یا کسی منتظم سے کہیں۔','Your biography, statement, and portfolio link were erased. Your email address was kept on file — your account is currently banned, and it\'s the only way this site can continue to enforce that.'=>'آپ کی سوانح، بیان، اور پورٹ فولیو لنک مٹا دیے گئے۔ آپ کا ای میل پتہ فائل میں رکھا گیا — آپ کا اکاؤنٹ فی الحال ممنوع ہے، اور اسی واحد طریقے سے یہ سائٹ اس پابندی کو نافذ رکھ سکتی ہے۔','[message removed]'=>'[پیغام ہٹا دیا گیا]','Vouch messages you wrote were redacted. Governance votes you cast were kept as-is — a vote is a community record, not personal data, and removing it would silently change a settled decision.'=>'آپ کے لکھے ہوئے واؤچ پیغامات حذف کر دیے گئے۔ آپ کے دیے گئے حکمرانی ووٹ اپنی اصل حالت میں رکھے گئے — ووٹ کمیونٹی کا ریکارڈ ہے، ذاتی ڈیٹا نہیں، اور اسے ہٹانے سے طے شدہ فیصلے میں خاموشی سے تبدیلی آ جائے گی۔','Past newsletter delivery records were anonymized; per-issue delivery counts were kept for statistics.'=>'گزشتہ نیوز لیٹر کی ترسیل کے ریکارڈ بے نام کر دیے گئے؛ ہر شمارے کی ترسیل کی تعداد اعدادوشمار کے لیے برقرار رکھی گئی۔','Transaction (donation/sale) records were kept in full — financial records are subject to a legal retention obligation and are exempt from erasure under GDPR Art. 17(3)(b).'=>'لین دین (عطیہ/فروخت) کے ریکارڈ مکمل طور پر برقرار رکھے گئے — مالی ریکارڈز پر قانونی تحفظِ مدت کی پابندی لاگو ہوتی ہے اور یہ GDPR آرٹیکل 17(3)(b) کے تحت حذف کرنے سے مستثنیٰ ہیں۔','Agnosis is a federated art-publishing plugin. The following is a starting point for describing what it collects — review and adapt it to your site\'s actual configuration before publishing.'=>'ایگنوسِس ایک وفاقی آرٹ پبلشنگ پلگ اِن ہے۔ ذیل میں اس بات کی وضاحت کے لیے ایک ابتدائی متن دیا گیا ہے کہ یہ کیا جمع کرتا ہے — شائع کرنے سے پہلے اسے اپنی سائٹ کی اصل ترتیب کے مطابق جانچیں اور ڈھالیں۔','What personal data we collect and why'=>'ہم کون سا ذاتی ڈیٹا جمع کرتے ہیں اور کیوں','When you apply to join, we store your email address, display name, biography, statement, and portfolio link to run the community vouching process. When you email us artwork, a biography, or an event, the content of that email (including your address) is stored while it is processed and reviewed. When you subscribe to our newsletter or message an artist through their contact form, we store your email address (and, for contact messages, your IP address) to deliver that message or send you future issues.'=>'جب آپ شامل ہونے کے لیے درخواست دیتے ہیں، ہم کمیونٹی واؤچنگ عمل چلانے کے لیے آپ کا ای میل پتہ، ظاہری نام، سوانح، بیان، اور پورٹ فولیو لنک محفوظ کرتے ہیں۔ جب آپ ہمیں آرٹ ورک، سوانح، یا کوئی تقریب ای میل کرتے ہیں، تو اس ای میل کا مواد (بشمول آپ کا پتہ) اس وقت تک محفوظ رہتا ہے جب تک اس پر کارروائی اور جائزہ لیا جا رہا ہو۔ جب آپ ہمارے نیوز لیٹر کو سبسکرائب کرتے ہیں یا رابطہ فارم کے ذریعے کسی فنکار کو پیغام بھیجتے ہیں، ہم وہ پیغام پہنچانے یا آپ کو آئندہ شمارے بھیجنے کے لیے آپ کا ای میل پتہ (اور رابطہ پیغامات کے لیے، آپ کا آئی پی پتہ) محفوظ کرتے ہیں۔','Who we share it with'=>'ہم اسے کس کے ساتھ شیئر کرتے ہیں','Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI or Anthropic, depending on this site\'s configuration) to help write publication text and enhance images. If this site instead uses WordPress\'s own built-in AI Client (configured under Settings → Connectors), submitted content is sent to whichever AI service that connector points to instead. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.'=>'Submitted artwork descriptions and images may be sent to a third-party AI provider (OpenAI or Anthropic, depending on this site\'s configuration) to help write publication text and enhance images. If this site instead uses WordPress\'s own built-in AI Client (configured under Settings → Connectors), submitted content is sent to whichever AI service that connector points to instead. Approved posts are also broadcast publicly over ActivityPub (the Fediverse) as part of this plugin\'s core federation feature.','How long we retain your data'=>'ہم آپ کا ڈیٹا کتنی مدت تک محفوظ رکھتے ہیں','Retention varies by data type; see this site\'s administrator for specifics. You can request a copy of, or the erasure of, the personal data described above at any time using this site\'s standard WordPress data request tools.'=>'برقرار رکھنے کی مدت ڈیٹا کی قسم کے لحاظ سے مختلف ہوتی ہے؛ تفصیلات کے لیے اس سائٹ کے منتظم سے رجوع کریں۔ آپ کسی بھی وقت اس سائٹ کے معیاری ورڈپریس ڈیٹا درخواست ٹولز استعمال کر کے اوپر بیان کردہ ذاتی ڈیٹا کی نقل، یا اس کے حذف کیے جانے، کی درخواست کر سکتے ہیں۔','Submitted text and images may be processed by a third-party AI provider. Approved posts are published publicly and shared across the Fediverse — this cannot be fully undone later.'=>'جمع کرایا گیا متن اور تصاویر کسی تیسرے فریق کے اے آئی فراہم کنندہ کے ذریعے پروسیس کی جا سکتی ہیں۔ منظور شدہ پوسٹس عوامی طور پر شائع کی جاتی ہیں اور فیڈیورس میں شیئر کی جاتی ہیں — بعد میں اسے مکمل طور پر واپس نہیں لیا جا سکتا۔','Your message may be reviewed by an automated content filter before being sent to the artist.'=>'آپ کے پیغام کو فنکار کو بھیجے جانے سے پہلے خودکار مواد فلٹر کے ذریعے جانچا جا سکتا ہے۔','See our %s for details.'=>'تفصیلات کے لیے ہماری %s دیکھیں۔','Privacy Policy'=>'رازداری کی پالیسی','Too many requests. Please wait %d seconds and try again.'=>'بہت زیادہ درخواستیں۔ براہِ کرم %d سیکنڈ انتظار کریں اور دوبارہ کوشش کریں۔','Submission limit reached. Please wait before sending again.'=>'جمع کرانے کی حد پوری ہو گئی ہے۔ براہِ کرم دوبارہ بھیجنے سے پہلے انتظار کریں۔','Please complete the verification check and try again.'=>'براہِ کرم تصدیقی جانچ مکمل کریں اور دوبارہ کوشش کریں۔','Could not verify you\'re human right now. Please try again in a moment.'=>'اس وقت یہ تصدیق نہیں ہو سکی کہ آپ انسان ہیں۔ براہِ کرم تھوڑی دیر بعد دوبارہ کوشش کریں۔','Verification failed. Please try again.'=>'تصدیق ناکام ہو گئی۔ براہِ کرم دوبارہ کوشش کریں۔','Every 5 minutes'=>'ہر 5 منٹ بعد','IMAP credentials are not configured.'=>'IMAP اسناد ترتیب نہیں دی گئیں۔','Connected successfully. %1$d message(s) in inbox, %2$d unseen.'=>'کامیابی سے جڑ گیا۔ ان باکس میں %1$d پیغام، %2$d غیر دیکھی ہوئی۔','Webhook secret not configured.'=>'Webhook راز ترتیب نہیں دیا گیا۔','Invalid or missing webhook signature.'=>'Webhook دستخط غلط ہے یا موجود نہیں۔','Webhook request timestamp is missing, malformed, or too old.'=>'Webhook درخواست کا وقت موجود نہیں، غلط شکل میں ہے، یا بہت پرانا ہے۔','This webhook request has already been processed.'=>'یہ webhook درخواست پہلے ہی پراسیس کی جا چکی ہے۔','No such artist actor.'=>'No such artist actor.','Sensitive content'=>'Sensitive content','OpenSSL is required for HTTP Signature verification.'=>'HTTP Signature کی تصدیق کے لیے OpenSSL درکار ہے۔','Signature header is required.'=>'Signature ہیڈر درکار ہے۔','Signature header is missing required fields (keyId, headers, signature).'=>'Signature ہیڈر میں مطلوبہ فیلڈز (keyId, headers, signature) موجود نہیں ہیں۔','Signature must cover the Date header.'=>'Signature must cover the Date header.','Signature on a POST request must cover the Digest header.'=>'Signature on a POST request must cover the Digest header.','Request date is too old or too far in the future.'=>'درخواست کی تاریخ بہت پرانی ہے یا مستقبل میں بہت زیادہ دور ہے۔','Signature value is not valid base64.'=>'Signature کی قدر درست base64 نہیں ہے۔','HTTP Signature verification failed.'=>'HTTP Signature کی تصدیق ناکام ہو گئی۔','Digest header does not match the request body.'=>'Digest ہیڈر درخواست کے body سے مطابقت نہیں رکھتا۔','keyId in Signature header is not a valid URL.'=>'Signature ہیڈر میں keyId درست URL نہیں ہے۔','Actor document could not be fetched (cached failure).'=>'Actor document could not be fetched (cached failure).','Failed to fetch actor document.'=>'actor document حاصل نہیں کیا جا سکا۔','Actor document returned a non-200 response.'=>'actor document نے 200 کے علاوہ جواب واپس کیا۔','Actor document does not contain a publicKey.publicKeyPem field.'=>'actor document میں publicKey.publicKeyPem فیلڈ موجود نہیں ہے۔','Node URL is required.'=>'Node URL درکار ہے۔','Contact %s'=>'%s سے رابطہ کریں','Contact this artist'=>'اس فنکار سے رابطہ کریں','Get in touch with %s'=>'%s سے رابطہ کریں','Get in touch'=>'رابطہ کریں','This newsletter issue could not be found.'=>'یہ نیوزلیٹر شمارہ نہیں مل سکا۔','Issue not found'=>'شمارہ نہیں ملا','Newsletter archive'=>'نیوزلیٹر آرکائیو','Past issues of the %s newsletter.'=>'%s نیوزلیٹر کے پچھلے شمارے۔','No issues have gone out yet — check back soon.'=>'ابھی تک کوئی شمارہ جاری نہیں ہوا — جلد واپس چیک کریں۔','← Newer'=>'← نئے','Older →'=>'پرانے →','Newsletter archive — %s'=>'نیوزلیٹر آرکائیو — %s','%1$s Newsletter — %2$s'=>'%1$s نیوزلیٹر — %2$s','%s Newsletter'=>'%s نیوزلیٹر','Nothing new to report this time — but the community is still here, and the next issue will have more.'=>'اس بار رپورٹ کرنے کے لیے کچھ نیا نہیں — لیکن کمیونٹی اب بھی موجود ہے، اور اگلے شمارے میں مزید ہوگا۔','New artwork'=>'نیا فن پارہ','Upcoming events'=>'آنے والے ایونٹس','%d new artwork published'=>'%d نئے فن پارے شائع ہوئے' . "\0" . '%d نئے فن پارے شائع ہوئے','%d new event announced'=>'%d نیا ایونٹ اعلان کیا گیا' . "\0" . '%d نئے ایونٹس اعلان کیے گئے','Welcome to our newest member: %s'=>'ہمارے نئے رکن کا خیرمقدم ہے: %s' . "\0" . 'ہمارے نئے اراکین کا خیرمقدم ہے: %s','%d community vote is open — check your email for your personal voting link.'=>'%d کمیونٹی ووٹ کھلا ہے — اپنی ذاتی ووٹنگ لنک کے لیے اپنی ای میل چیک کریں۔' . "\0" . '%d کمیونٹی ووٹ کھلے ہیں — اپنی ذاتی ووٹنگ لنکس کے لیے اپنی ای میل چیک کریں۔','Recent work from the community'=>'کمیونٹی کا حالیہ کام','…and %d more.'=>'…اور %d مزید۔' . "\0" . '…اور %d مزید۔','Community Newsletter'=>'کمیونٹی نیوز لیٹر','Having trouble viewing this email?'=>'کیا آپ کو یہ ای میل دیکھنے میں مشکل ہو رہی ہے؟','View it online.'=>'اسے آن لائن دیکھیں۔','Unsubscribe'=>'سبسکرائب ختم کریں','Subscribe to get these by email'=>'یہ ای میل کے ذریعے حاصل کرنے کے لیے سبسکرائب کریں','[%s] Community newsletter'=>'[%s] کمیونٹی نیوز لیٹر','[%s] Newsletter'=>'[%s] نیوز لیٹر','Get new artworks, artist admissions, and community updates in your inbox.'=>'نئی آرٹ ورکس، فنکاروں کی درخواستیں، اور کمیونٹی اپ ڈیٹس اپنے ان باکس میں حاصل کریں۔','Subscribe to the newsletter'=>'نیوز لیٹر کے لیے سبسکرائب کریں','Unknown newsletter type.'=>'نیوز لیٹر کی قسم نامعلوم ہے۔','A previous issue is still sending — please wait for it to finish.'=>'پچھلا شمارہ اب بھی بھیجا جا رہا ہے — براہِ کرم اس کے مکمل ہونے کا انتظار کریں۔','Please enter a valid email address to send the test to.'=>'براہِ کرم ٹیسٹ بھیجنے کے لیے ایک درست ای میل پتہ درج کریں۔','This is a TEST send — it previews the next issue using the current draft intro and recent activity. It was not counted as a real send and no subscribers were emailed. The unsubscribe link below is a non-functional placeholder.'=>'یہ ایک ٹیسٹ ارسال ہے — یہ موجودہ ڈرافٹ تعارف اور حالیہ سرگرمی استعمال کرتے ہوئے اگلے شمارے کا پیش منظر دکھاتا ہے۔ اسے حقیقی ارسال شمار نہیں کیا گیا اور کسی سبسکرائبر کو ای میل نہیں بھیجی گئی۔ نیچے دیا گیا ان سبسکرائب لنک ایک غیر فعال پلیس ہولڈر ہے۔','The %1$s at %2$s is due to send in about a day. Agnosis drafted an intro from what\'s new since the last issue:'=>'%2$s پر %1$s تقریباً ایک دن میں ارسال ہونے والا ہے۔ Agnosis نے آخری شمارے کے بعد کی نئی چیزوں سے ایک تعارف تیار کیا ہے:','It\'s already saved and will be used as-is if you don\'t act — review it, rewrite it, or clear it back to blank here:'=>'یہ پہلے ہی محفوظ ہو چکا ہے اور اگر آپ کوئی اقدام نہ کریں تو اسی طرح استعمال ہوگا — اسے یہاں دیکھیں، دوبارہ لکھیں، یا واپس خالی کر دیں:','%1$s intro drafted for %2$s — review before it sends'=>'%2$s کے لیے %1$s تعارف تیار کیا گیا — بھیجے جانے سے پہلے جائزہ لیں','Subscribe'=>'سبسکرائب کریں','See past issues'=>'پرانے شمارے دیکھیں','Almost there — check your inbox for a confirmation link.'=>'تقریباً مکمل — تصدیقی لنک کے لیے اپنا ان باکس چیک کریں۔','[%s] Confirm your newsletter subscription'=>'[%s] اپنی نیوز لیٹر سبسکرپشن کی تصدیق کریں','Thanks for signing up! Confirm your email address to start receiving the newsletter.'=>'سبسکرائب کرنے کا شکریہ! نیوز لیٹر وصول کرنا شروع کرنے کے لیے اپنا ای میل پتہ تصدیق کریں۔','Confirm subscription'=>'سبسکرپشن کی تصدیق کریں','If you didn\'t request this, simply ignore this email — you will not be subscribed.'=>'اگر آپ نے یہ درخواست نہیں کی تھی، تو بس اس ای میل کو نظر انداز کر دیں — آپ کی سبسکرپشن نہیں ہوگی۔','Artists are automatically subscribed — there is nothing to confirm.'=>'فنکار خودکار طور پر سبسکرائب ہوتے ہیں — یہاں تصدیق کرنے کے لیے کچھ نہیں۔','Subscription confirmed'=>'سبسکرپشن کی تصدیق ہوگئی','You\'re all set — the newsletter will land in your inbox from now on.'=>'اب سب کچھ تیار ہے — نیوز لیٹر اب سے آپ کے ان باکس میں آئے گا۔','Unsubscribed'=>'سبسکرپشن ختم ہوگئی','You will no longer receive the newsletter. Sorry to see you go.'=>'اب آپ کو نیوز لیٹر موصول نہیں ہوگا۔ آپ کے جانے کا افسوس ہے۔','This unsubscribe link is invalid or has already been used.'=>'یہ ان سبسکرائب لنک غیر درست ہے یا پہلے ہی استعمال ہو چکا ہے۔','This unsubscribe link is invalid or has been tampered with.'=>'یہ ان سبسکرائب لنک غیر درست ہے یا اس میں چھیڑ چھاڑ کی گئی ہے۔','Account not found.'=>'اکاؤنٹ نہیں ملا۔','You will no longer receive the artist newsletter. You can re-subscribe any time from your submissions page.'=>'اب آپ کو آرٹسٹ نیوز لیٹر موصول نہیں ہوگا۔ آپ اپنی سبمشنز صفحہ سے کسی بھی وقت دوبارہ سبسکرائب کر سکتے ہیں۔','Confirm your subscription?'=>'کیا آپ اپنی سبسکرپشن کی تصدیق کرنا چاہتے ہیں؟','You\'ll start receiving the newsletter once you confirm below.'=>'نیچے تصدیق کرنے کے بعد آپ نیوز لیٹر وصول کرنا شروع کریں گے۔','Unsubscribe from the newsletter?'=>'کیا آپ نیوز لیٹر سے سبسکرپشن ختم کرنا چاہتے ہیں؟','You will stop receiving the newsletter once you confirm below.'=>'نیچے تصدیق کرنے کے بعد آپ کو نیوز لیٹر موصول ہونا بند ہو جائے گا۔','Confirm unsubscribe'=>'سبسکرپشن ختم کرنے کی تصدیق کریں','That doesn\'t look like a valid web address.'=>'یہ درست ویب ایڈریس معلوم نہیں ہوتا۔','This site isn\'t on this Agnosis node\'s list of trusted platforms, and automatic link review is turned off here.'=>'یہ سائٹ Agnosis node کی قابلِ اعتماد پلیٹ فارمز کی فہرست میں شامل نہیں ہے، اور یہاں خودکار لنک جائزہ بند ہے۔','This node couldn\'t safely load that page to review it (it may be unreachable, or blocked for security reasons).'=>'یہ node اس صفحے کو جائزے کے لیے محفوظ طریقے سے لوڈ نہیں کر سکا (ممکن ہے یہ دستیاب نہ ہو، یا حفاظتی وجوہات کی بنا پر بلاک ہو)۔','Automatic review of that page\'s content was inconclusive.'=>'اس صفحے کے مواد کا خودکار جائزہ قطعی نتیجہ نہیں دے سکا۔','Automatic review found that page\'s content isn\'t allowed to be embedded on this site.'=>'خودکار جائزے سے معلوم ہوا کہ اس صفحے کا مواد اس سائٹ پر ایمبیڈ کرنے کی اجازت نہیں دیتا۔','Gallery overview'=>'گیلری کا جائزہ','Feature this artwork in the gallery overview'=>'اس آرٹ ورک کو گیلری کے جائزے میں نمایاں کریں','Featured artworks are always chosen first when selecting one work per artist for the homepage overview.'=>'نمایاں آرٹ ورکس ہمیشہ ہوم پیج جائزے کے لیے ہر فنکار سے ایک کام منتخب کرتے وقت پہلے چنے جاتے ہیں۔','[Agnosis] Confirm removal of: %s'=>'[Agnosis] اس چیز کو ہٹانے کی تصدیق کریں: %s','[%s] We couldn\'t find that artwork or event'=>'[%s] ہم وہ آرٹ ورک یا ایونٹ نہیں ڈھونڈ سکے','[%s] Your artwork is now featured'=>'[%s] آپ کا آرٹ ورک اب نمایاں کر دیا گیا ہے','[%s] We couldn\'t find that artwork'=>'[%s] ہم وہ آرٹ ورک نہیں ڈھونڈ سکے','We received a removal request for "%s", but couldn\'t find an artwork or event with that exact title in your account.'=>'ہمیں "%s" کو ہٹانے کی درخواست ملی، لیکن ہمیں آپ کے اکاؤنٹ میں اس بالکل اسی عنوان والا کوئی آرٹ ورک یا ایونٹ نہیں ملا۔','We received a request to feature "%s", but couldn\'t find a published artwork with that exact title in your account.'=>'ہمیں "%s" کو نمایاں کرنے کی درخواست ملی، لیکن ہمیں آپ کے اکاؤنٹ میں اس بالکل اسی عنوان والا کوئی شائع شدہ آرٹ ورک نہیں ملا۔','Did you mean "%s"?'=>'کیا آپ کی مراد "%s" تھی؟','Yes, remove this instead'=>'جی ہاں، اس کے بجائے اسے ہٹا دیں','Or simply resend your original email with that exact title.'=>'یا بس اپنا اصل ای میل اسی بالکل درست عنوان کے ساتھ دوبارہ بھیج دیں۔','Resend your original email with that exact title.'=>'اپنا اصل ای میل اسی بالکل درست عنوان کے ساتھ دوبارہ بھیجیں۔','Your current titles:'=>'آپ کے موجودہ عنوانات:','Titles are matched exactly, so a small difference in wording is enough to miss — double-check spelling, capitalization, and punctuation against the list above before resending.'=>'عنوانات کا بالکل درست میچ ہوتا ہے، اس لیے الفاظ میں معمولی سا فرق بھی عدم مطابقت کا سبب بن سکتا ہے — دوبارہ بھیجنے سے پہلے اوپر دی گئی فہرست کے مطابق ہجے، بڑے/چھوٹے حروف، اور رموزِ اوقاف دوبارہ چیک کریں۔','"%s" is now your featured artwork on the gallery overview.'=>'"%s" اب گیلری اوورویو میں آپ کا نمایاں آرٹ ورک ہے۔','Any previously featured artwork has been unfeatured automatically — only one piece is featured at a time.'=>'پہلے سے نمایاں کوئی بھی آرٹ ورک خود بخود غیر نمایاں کر دیا گیا ہے — ایک وقت میں صرف ایک ہی کام نمایاں ہوتا ہے۔','[Agnosis] Your submission is ready to review: %s'=>'[Agnosis] آپ کی جمع کرائی گئی چیز جائزے کے لیے تیار ہے: %s','event'=>'ایونٹ','artwork'=>'آرٹ ورک','We received a removal request for the following %s:'=>'ہمیں درج ذیل %s کو ہٹانے کی درخواست ملی ہے:','If you want to permanently remove this %s, click the button below. This action cannot be undone.'=>'اگر آپ اس %s کو ہمیشہ کے لیے ہٹانا چاہتے ہیں، تو نیچے دیا گیا بٹن دبائیں۔ اس کارروائی کو واپس نہیں کیا جا سکتا۔','Yes, remove this %s'=>'جی ہاں، اس %s کو ہٹا دیں','If you did not request this removal, simply ignore this email — your %s will remain published.'=>'اگر آپ نے یہ حذف کرنے کی درخواست نہیں کی تھی، تو بس اس ای میل کو نظر انداز کر دیں — آپ کا %s شائع رہیں گے۔','This confirmation link expires in 7 days.'=>'یہ تصدیقی لنک 7 دن میں ختم ہو جائے گا۔','📷 Photo enhanced automatically'=>'📷 تصویر خودکار طور پر بہتر بنا دی گئی','We detected some photographic issues and applied AI correction to improve visibility of your artwork:'=>'ہم نے کچھ فوٹوگرافی مسائل کا پتہ لگایا اور آپ کے آرٹ ورک کی بہتر نمائش کے لیے AI درستی نافذ کی:','The artwork itself has not been altered — only the photograph quality was corrected.'=>'خود آرٹ ورک میں کوئی تبدیلی نہیں کی گئی — صرف تصویر کے معیار کو درست کیا گیا ہے۔','📷 Photo quality score: %d/10'=>'📷 تصویر کا معیار اسکور: %d/10','Double-check the link is correct — you can fix or remove it in the form below before publishing.'=>'لنک درست ہے یا نہیں، دوبارہ چیک کریں — شائع کرنے سے پہلے آپ نیچے دیے گئے فارم میں اسے درست یا ہٹا سکتے ہیں۔','If the link was correct, its destination may simply not be from a source this site automatically embeds.'=>'اگر لنک درست تھا، تو ممکن ہے اس کی منزل ایسی نہ ہو جسے یہ سائٹ خودکار طور پر ایمبیڈ کرتی ہو۔','🔗 A link was not included'=>'🔗 کوئی لنک شامل نہیں کیا گیا' . "\0" . '🔗 کچھ لنکس شامل نہیں کیے گئے','The following couldn\'t be automatically embedded, so they were left out:'=>'مندرجہ ذیل کو خودکار طور پر ایمبیڈ نہیں کیا جا سکا، اس لیے انہیں شامل نہیں کیا گیا:','Its subject line didn\'t exactly match one of your existing titles. If you meant to update an existing event, "%s", resend your email with that exact title instead.'=>'اس کی موضوعی سطر آپ کے موجودہ عنوانات میں سے کسی سے بالکل نہیں ملتی تھی۔ اگر آپ کا مطلب کسی موجودہ ایونٹ "%s" کو اپ ڈیٹ کرنا تھا، تو اس کے بجائے اپنا ای میل اسی بالکل درست عنوان کے ساتھ دوبارہ بھیجیں۔','Its subject line didn\'t exactly match one of your existing titles. If you meant to replace an existing artwork, "%s", resend your email with that exact title instead.'=>'اس کی موضوعی سطر آپ کے موجودہ عنوانات میں سے کسی سے بالکل نہیں ملتی تھی۔ اگر آپ کا مطلب کسی موجودہ آرٹ ورک "%s" کو بدلنا تھا، تو اس کے بجائے اپنا ای میل اسی بالکل درست عنوان کے ساتھ دوبارہ بھیجیں۔','📄 This was published as a new post'=>'📄 یہ ایک نئی پوسٹ کے طور پر شائع کیا گیا','Your submission has been processed. Here\'s what our AI curator came up with — take a look and let us know if it\'s ready to publish.'=>'آپ کی جمع کرائی گئی چیز پر کارروائی ہو گئی ہے۔ یہ رہی وہ چیز جو ہمارے AI کیوریٹر نے تیار کی ہے — ذرا دیکھیں اور ہمیں بتائیں کہ کیا یہ شائع کرنے کے لیے تیار ہے۔','On the site: %s'=>'سائٹ پر: %s','In your language: %s'=>'آپ کی زبان میں: %s','Looks great — Publish it'=>'بہت اچھا لگ رہا ہے — اسے شائع کریں','Discard'=>'رد کریں','Want to tweak the title, text or tags before publishing?'=>'شائع کرنے سے پہلے عنوان، متن یا ٹیگز میں کچھ ردوبدل کرنا چاہتے ہیں؟','Open your submissions page →'=>'اپنا submissions صفحہ کھولیں →','The Publish and Discard links above expire in %d day. Your submission stays as a draft until you decide.'=>'اوپر دیے گئے Publish اور Discard لنکس %d دن میں ختم ہو جاتے ہیں۔ آپ کی جمع کرائی گئی چیز اس وقت تک ڈرافٹ رہتی ہے جب تک آپ فیصلہ نہ کریں۔' . "\0" . 'اوپر دیے گئے Publish اور Discard لنکس %d دنوں میں ختم ہو جاتے ہیں۔ آپ کی جمع کرائی گئی چیز اس وقت تک ڈرافٹ رہتی ہے جب تک آپ فیصلہ نہ کریں۔','[%s] We couldn\'t process your submission'=>'[%s] ہم آپ کی جمع کرائی گئی چیز پر کارروائی نہیں کر سکے','[%s] We couldn\'t find a photo in your email'=>'[%s] ہمیں آپ کے ای میل میں کوئی تصویر نہیں ملی','We received your email, but couldn\'t process a usable photo, audio, or video file from it — so nothing was published. This can happen when an image is pasted or inserted inline rather than added as a proper attachment, or when a file arrives in a format this server can\'t convert (for example, an iPhone photo saved in HEIC/HEIF format).'=>'ہمیں آپ کا ای میل مل گیا، لیکن اس سے کوئی قابلِ استعمال تصویر، آڈیو، یا ویڈیو فائل پروسیس نہیں ہو سکی — اس لیے کچھ بھی شائع نہیں کیا گیا۔ یہ اس وقت ہو سکتا ہے جب تصویر منسلک کرنے کے بجائے پیسٹ کی گئی ہو یا پیغام کے باڈی میں براہِ راست شامل کی گئی ہو، یا جب فائل ایسے فارمیٹ میں آئے جسے یہ سرور تبدیل نہ کر سکے (مثلاً HEIC/HEIF فارمیٹ میں محفوظ آئی فون تصویر)۔','To resend correctly:'=>'درست طریقے سے دوبارہ بھیجنے کے لیے:','Use your mail app\'s "Attach file" (usually a paperclip icon) rather than "Insert photo" or pasting the image directly into the message body.'=>'اپنی میل ایپ میں "Attach file" (عام طور پر پیپرکلپ آئیکن) استعمال کریں، نہ کہ "Insert photo" یا تصویر کو براہِ راست پیغام کے متن میں پیسٹ کریں۔','If your photo was taken on an iPhone, try switching Settings → Camera → Formats to "Most Compatible" before taking or sending it, or use "Options" in Mail to send it as a JPEG.'=>'اگر آپ کی تصویر آئی فون پر لی گئی تھی، تو اسے لینے یا بھیجنے سے پہلے Settings → Camera → Formats میں "Most Compatible" پر سوئچ کرنے کی کوشش کریں، یا Mail میں "Options" استعمال کر کے اسے JPEG کے طور پر بھیجیں۔','Supported formats: JPEG, PNG, WebP, GIF, TIFF, or HEIC/HEIF for images; MP3, WAV, M4A, OGG, or FLAC for audio; MP4, MOV, AVI, WebM, OGG, or MPEG for video.'=>'معاون فارمیٹس: تصاویر کے لیے JPEG، PNG، WebP، GIF، TIFF، یا HEIC/HEIF؛ آڈیو کے لیے MP3، WAV، M4A، OGG، یا FLAC؛ ویڈیو کے لیے MP4، MOV، AVI، WebM، OGG، یا MPEG۔','Once it\'s properly attached, just send it to the same address again — we\'ll pick it up automatically.'=>'جیسے ہی یہ درست طریقے سے منسلک ہو جائے، بس اسے دوبارہ اسی پتے پر بھیج دیں — ہم اسے خودکار طور پر حاصل کر لیں گے۔','The photo is too dark to show your artwork clearly. Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'تصویر اتنی تاریک ہے کہ آپ کا فن پارہ واضح طور پر نظر نہیں آ رہا۔ دن کی روشنی میں کسی بڑی کھڑکی کے قریب تصویر لیں، یا کام پر سائیڈ سے نرم لیمپ کی روشنی ڈالیں۔','The photo is underexposed (too dark). Try photographing near a large window in daylight, or use a soft lamp aimed at the work from the side.'=>'تصویر کم روشنی کی ہے (بہت تاریک)۔ دن کی روشنی میں کسی بڑی کھڑکی کے قریب تصویر لیں، یا کام پر سائیڈ سے نرم لیمپ کی روشنی ڈالیں۔','The photo is overexposed (too bright / washed out). Avoid direct sunlight or flash pointed straight at the artwork — diffuse or indirect light works best.'=>'تصویر حد سے زیادہ روشن ہے (بہت زیادہ روشن / دھلی ہوئی)۔ براہِ راست دھوپ یا فن پارے کی طرف سیدھا فلیش نہ کریں — بکھری ہوئی یا بالواسطہ روشنی بہتر کام کرتی ہے۔','The photo is too bright or washed out. Avoid direct sunlight or flash — diffuse light or shade gives more even tones.'=>'تصویر بہت روشن یا دھلی ہوئی لگ رہی ہے۔ براہِ راست دھوپ یا فلیش سے بچیں — بکھری ہوئی روشنی یا سایہ زیادہ یکساں رنگ دیتا ہے۔','There is glare or a bright reflection on the artwork. Tilt the canvas slightly or photograph at an angle to eliminate reflections from the surface.'=>'فن پارے پر چمک یا روشن انعکاس موجود ہے۔ کینوس کو ہلکا سا جھکا دیں یا زاویے سے تصویر لیں تاکہ سطح کے انعکاس ختم ہو جائیں۔','There is a reflection on the artwork surface. Tilt the canvas slightly or change your angle to eliminate it.'=>'فن پارے کی سطح پر انعکاس موجود ہے۔ اسے ختم کرنے کے لیے کینوس کو ہلکا سا جھکا دیں یا اپنا زاویہ بدلیں۔','The image is blurry. Rest your phone or camera on a stable surface, use the self-timer, and make sure the artwork fills most of the frame so autofocus locks on it.'=>'تصویر دھندلی ہے۔ اپنا فون یا کیمرہ کسی مضبوط سطح پر رکھیں، خودکار ٹائمر استعمال کریں، اور یقینی بنائیں کہ فن پارہ فریم کا زیادہ تر حصہ گھیرے تاکہ آٹو فوکس اس پر لاک ہو جائے۔','The image is out of focus. Tap on the artwork on your phone screen before shooting to make sure autofocus locks on it, and hold the camera still.'=>'تصویر فوکس سے باہر ہے۔ تصویر لینے سے پہلے اپنے فون کی اسکرین پر فن پارے پر ٹیپ کریں تاکہ آٹو فوکس اس پر لاک ہو جائے، اور کیمرہ ساکت رکھیں۔','There is motion blur. Hold the camera very still or use a tripod; press the shutter gently or use the self-timer to avoid shake.'=>'حرکت کی دھندلاہٹ موجود ہے۔ کیمرہ بالکل ساکت رکھیں یا ٹرائی پوڈ استعمال کریں؛ شٹر آہستگی سے دبائیں یا جھٹکا سے بچنے کے لیے خودکار ٹائمر استعمال کریں۔','Camera shake is visible. Use a tripod or rest the camera on a flat surface and use the self-timer to avoid movement when pressing the shutter.'=>'کیمرے کے ہلنے کے آثار نظر آ رہے ہیں۔ ٹرائی پوڈ استعمال کریں یا کیمرے کو کسی ہموار سطح پر رکھیں اور شٹر دبانے کے وقت حرکت سے بچنے کے لیے خودکار ٹائمر استعمال کریں۔','The image resolution is too low. Use your phone\'s highest quality setting and make sure you\'re close enough that the artwork fills the frame.'=>'تصویر کی ریزولوشن بہت کم ہے۔ اپنے فون کی اعلیٰ ترین کوالٹی سیٹنگ استعمال کریں اور یقینی بنائیں کہ آپ اتنے قریب ہیں کہ فن پارہ فریم کو بھر دے۔','The image resolution is too low. Use your phone\'s highest quality setting and fill the frame with the artwork.'=>'تصویر کی ریزولوشن بہت کم ہے۔ اپنے فون کی اعلیٰ ترین کوالٹی سیٹنگ استعمال کریں اور فن پارے سے فریم بھر دیں۔','The image is pixelated. Shoot from closer or use a higher resolution setting on your camera.'=>'تصویر پکسل زدہ ہے۔ قریب سے تصویر لیں یا اپنے کیمرے میں زیادہ ریزولوشن سیٹنگ استعمال کریں۔','The photo has a strong color cast. Shoot under neutral daylight or use your phone\'s Auto White Balance setting for more accurate colors.'=>'تصویر میں رنگوں کا مضبوط شیڈ نظر آ رہا ہے۔ غیر جانبدار دن کی روشنی میں تصویر لیں یا زیادہ درست رنگوں کے لیے اپنے فون کی آٹو وائٹ بیلنس سیٹنگ استعمال کریں۔','The photo looks too yellow or warm. Shoot under natural daylight or switch your phone\'s white balance to Daylight / Cloudy.'=>'تصویر بہت زرد یا گرم لگ رہی ہے۔ قدرتی دن کی روشنی میں تصویر لیں یا اپنے فون کی وائٹ بیلنس سیٹنگ کو Daylight / Cloudy پر بدلیں۔','The photo has a cold blue tint. Move the artwork to a warmer, more natural light source or adjust your camera\'s white balance.'=>'تصویر میں سرد نیلا رنگ جھلک رہا ہے۔ فن پارے کو کسی زیادہ گرم، زیادہ قدرتی روشنی کے ذریعے کے قریب لے جائیں یا اپنے کیمرے کی وائٹ بیلنس ایڈجسٹ کریں۔','Part of the artwork appears to be cropped out of the frame. Step back and make sure the entire work is visible before shooting.'=>'فن پارے کا کچھ حصہ فریم سے باہر کٹ گیا معلوم ہوتا ہے۔ تصویر لینے سے پہلے پیچھے ہٹیں اور یقینی بنائیں کہ پورا کام نظر آ رہا ہو۔','The artwork is photographed at an angle, causing distortion. Shoot straight on, with the camera parallel to the canvas.'=>'فن پارے کی تصویر زاویے سے لی گئی ہے، جس سے بگاڑ پیدا ہو رہا ہے۔ کیمرے کو کینوس کے متوازی رکھتے ہوئے سیدھا سامنے سے تصویر لیں۔','The artwork looks distorted or skewed. Position your camera directly in front of the artwork, parallel to its surface.'=>'فن پارہ بگڑا ہوا یا ٹیڑھا دکھائی دے رہا ہے۔ اپنا کیمرہ فن پارے کے بالکل سامنے، اس کی سطح کے متوازی رکھیں۔','There is a shadow across part of the artwork. Reposition your light source or move the artwork so no shadows fall on the surface.'=>'فن پارے کے ایک حصے پر سایہ پڑ رہا ہے۔ اپنے روشنی کے ذریعے کو دوبارہ ترتیب دیں یا فن پارے کو اس طرح منتقل کریں کہ سطح پر کوئی سایہ نہ پڑے۔','We received your submission, but unfortunately the photo quality is too low for us to show your artwork clearly. We didn\'t publish it — but please don\'t be discouraged! A simple retake is usually all it takes.'=>'ہمیں آپ کی جمع کرائی گئی چیز مل گئی ہے، لیکن بدقسمتی سے تصویر کا معیار اتنا کم ہے کہ ہم آپ کے فن پارے کو واضح طور پر دکھا نہیں سکتے۔ ہم نے اسے شائع نہیں کیا — لیکن براہِ کرم دل برداشتہ نہ ہوں! ایک سادہ سی دوبارہ تصویر لینے سے عموماً مسئلہ حل ہو جاتا ہے۔','📷 Photo quality score: %d / 10'=>'📷 تصویر کے معیار کا اسکور: %d / 10','Here\'s what our AI detected and how to fix it:'=>'یہ ہے جو ہمارے AI نے شناخت کیا اور اسے کیسے درست کیا جائے:','The overall photo quality was too low for our AI to process the artwork clearly.'=>'مجموعی تصویر کا معیار ہمارے AI کے لیے اتنا کم تھا کہ وہ فن پارے کو واضح طور پر پروسیس نہ کر سکا۔','💡 Quick tips for a great artwork photo'=>'💡 بہترین فن پارے کی تصویر کے لیے فوری تجاویز','Use natural light — position the artwork near a window on a cloudy day for even, soft light.'=>'قدرتی روشنی استعمال کریں — یکساں، نرم روشنی کے لیے فن پارے کو ابر آلود دن میں کھڑکی کے قریب رکھیں۔','Shoot straight on — hold your phone parallel to the canvas to avoid perspective distortion.'=>'سیدھا سامنے سے تصویر لیں — perspective distortion سے بچنے کے لیے اپنے فون کو کینوس کے متوازی رکھیں۔','Fill the frame — let the artwork take up most of the shot; crop out distracting backgrounds.'=>'فریم بھریں — فن پارے کو تصویر کے زیادہ تر حصے پر جگہ لینے دیں؛ توجہ ہٹانے والے پس منظر کو کاٹ دیں۔','Hold still — tap the artwork on your screen to focus, then press the shutter gently or use a self-timer.'=>'ساکت رہیں — فوکس کے لیے اپنے اسکرین پر فن پارے پر ٹیپ کریں، پھر شٹر آہستگی سے دبائیں یا خودکار ٹائمر استعمال کریں۔','Once you have a clearer photo, just email it to the same address as before — we\'ll pick it up automatically.'=>'جب آپ کے پاس زیادہ واضح تصویر ہو جائے، تو بس اسے پہلے والے اسی ای میل ایڈریس پر بھیج دیں — ہم اسے خودکار طور پر لے لیں گے۔','Your previous submission is saved in your submissions page in case you want to review what was sent.'=>'آپ کی پچھلی جمع کرائی گئی چیز آپ کے submissions صفحے میں محفوظ ہے، اگر آپ دیکھنا چاہیں کہ کیا بھیجا گیا تھا۔','View submissions →'=>'جمع کرائی گئی چیزیں دیکھیں →','Photo'=>'تصویر','%s (original)'=>'%s (اصل)','%s (poster frame)'=>'%s (پوسٹر فریم)','Failed to insert attachment.'=>'اٹیچمنٹ داخل کرنے میں ناکامی ہوئی۔','Artwork or event not found.'=>'فن پارہ یا ایونٹ نہیں ملا۔','%s already removed.'=>'%s پہلے ہی ہٹا دیا گیا ہے۔','Could not remove the %s. Please try again.'=>'%s کو ہٹایا نہیں جا سکا۔ براہِ کرم دوبارہ کوشش کریں۔','Your %s has been removed.'=>'آپ کا %s ہٹا دیا گیا ہے۔','A valid removal token is required.'=>'ایک درست removal token درکار ہے۔','No pending removal request found for this item.'=>'اس آئٹم کے لیے کوئی pending removal request نہیں ملی۔','The removal link has expired. Please send another removal request.'=>'حذف کرنے کا لنک ختم ہو چکا ہے۔ براہِ کرم حذف کرنے کی ایک اور درخواست بھیجیں۔','Invalid removal token.'=>'غلط removal token۔','View it live'=>'اسے لائیو دیکھیں','Biography published'=>'سوانح حیات شائع ہو گئی','Your biography has been published.'=>'آپ کی سوانح حیات شائع ہو گئی ہے۔','Event published'=>'ایونٹ شائع ہو گیا','The event has been published.'=>'ایونٹ شائع ہو گیا ہے۔','Artwork published'=>'فن پارہ شائع ہو گیا','The artwork has been published to the gallery.'=>'آرٹ ورک گیلری میں شائع کر دیا گیا ہے۔','Submission discarded'=>'جمع کروانا مسترد کر دیا گیا','The submission has been discarded.'=>'جمع کروانا مسترد کر دیا گیا ہے۔','Biography removed'=>'سوانح عمری ہٹا دی گئی','Your biography has been removed.'=>'آپ کی سوانح عمری ہٹا دی گئی ہے۔','Event removed'=>'ایونٹ ہٹا دیا گیا','The event has been removed.'=>'ایونٹ ہٹا دیا گیا ہے۔','Artwork removed'=>'آرٹ ورک ہٹا دیا گیا','Your artwork has been removed from the gallery.'=>'آپ کا آرٹ ورک گیلری سے ہٹا دیا گیا ہے۔','This link may have already been used or may have expired. Please log in to manage your submissions.'=>'ممکن ہے یہ لنک پہلے ہی استعمال ہو چکا ہو یا اس کی مدت ختم ہو چکی ہو۔ براہِ کرم اپنی جمع کروائی گئی چیزوں کا انتظام کرنے کے لیے لاگ اِن کریں۔','Title and full text cannot be empty. Fill them back in, or use "Discard" from the original email instead.'=>'عنوان اور مکمل متن خالی نہیں ہو سکتے۔ انہیں دوبارہ بھر دیں، یا اس کے بجائے اصل ای میل سے "Discard" استعمال کریں۔','The full text cannot be empty. Fill it back in, or use "Discard" from the original email instead.'=>'مکمل متن خالی نہیں ہو سکتا۔ اسے دوبارہ بھر دیں، یا اس کے بجائے اصل ای میل سے "Discard" استعمال کریں۔','Portfolio link'=>'پورٹ فولیو لنک','Social link %d (optional)'=>'سوشل لنک %d (اختیاری)','Hour'=>'گھنٹہ','Location'=>'مقام','Address'=>'پتہ','Timezone'=>'ٹائم زون','Other'=>'دیگر','— Not set —'=>'— سیٹ نہیں —','Discard this submission?'=>'کیا یہ جمع کروانا مسترد کر دیں؟','This will permanently discard the submission — it will not be published.'=>'اس سے جمع کروانا مستقل طور پر مسترد ہو جائے گا — اسے شائع نہیں کیا جائے گا۔','Yes, discard it'=>'جی ہاں، اسے مسترد کریں','Remove this artwork?'=>'کیا یہ آرٹ ورک ہٹا دیں؟','This will remove the published artwork from the gallery.'=>'اس سے شائع شدہ آرٹ ورک گیلری سے ہٹ جائے گا۔','Yes, remove it'=>'جی ہاں، اسے ہٹا دیں','Title'=>'عنوان','Short description'=>'مختصر تفصیل','Full text'=>'مکمل متن','Publish this %s?'=>'کیا یہ %s شائع کریں؟','Make any final changes below, or leave everything as-is to publish exactly what was drafted.'=>'نیچے کوئی بھی آخری تبدیلیاں کر لیں، یا اگر کچھ نہ بدلنا ہو تو بالکل اسی طرح شائع کرنے کے لیے چھوڑ دیں۔','Publish it'=>'اسے شائع کریں','biography'=>'سوانح عمری','Submission not found.'=>'جمع کروانا نہیں ملا۔','This submission is not awaiting review.'=>'یہ جمع کروانا جائزے کا منتظر نہیں ہے۔','The original published item could not be found.'=>'اصل شائع شدہ آئٹم نہیں مل سکا۔','You do not have permission to review this submission.'=>'آپ کو اس جمع کروانے کا جائزہ لینے کی اجازت نہیں ہے۔','Review link not found or already used.'=>'جائزے کا لنک نہیں ملا یا پہلے ہی استعمال ہو چکا ہے۔','Invalid review token.'=>'غلط جائزہ ٹوکن۔','This review link has expired. Please log in to manage your submissions.'=>'اس جائزہ لنک کی مدت ختم ہو چکی ہے۔ براہِ کرم اپنی جمع کروائی گئی چیزوں کا انتظام کرنے کے لیے لاگ اِن کریں۔','No submissions awaiting review.'=>'جائزے کے منتظر کوئی جمع کروانا موجود نہیں۔','Make changes'=>'تبدیلیاں کریں','One-line description'=>'ایک سطر کی تفصیل','Description'=>'تفصیل','Tags (comma-separated)'=>'ٹیگز (کاما سے جدا کیے گئے)','Save &amp; Publish'=>'محفوظ کریں اور شائع کریں','Publishing…'=>'شائع کیا جا رہا ہے…','Published ✓'=>'شائع ہو گیا ✓','Something went wrong.'=>'کچھ غلط ہو گیا۔','Could not connect. Please try again.'=>'رابطہ قائم نہیں ہو سکا۔ براہِ کرم دوبارہ کوشش کریں۔','Discard this submission? This cannot be undone.'=>'کیا یہ جمع کروانا مسترد کر دیں؟ اسے واپس نہیں کیا جا سکتا۔','Discarding…'=>'حذف کیا جا رہا ہے…','Discarded.'=>'حذف کر دیا گیا۔','Saving and publishing…'=>'محفوظ اور شائع کیا جا رہا ہے…','Log in to view your submissions'=>'اپنی جمع کرائی گئی چیزیں دیکھنے کے لیے لاگ اِن کریں','Username or email address'=>'صارف نام یا ای میل پتہ','Password'=>'پاس ورڈ','Log in'=>'لاگ اِن کریں','Remember me'=>'مجھے یاد رکھیں','Forgot your password?'=>'اپنا پاس ورڈ بھول گئے؟','Book'=>'کتاب','Person'=>'شخص','Calendar'=>'کیلنڈر','Pin'=>'پن','Baseline (default)'=>'بنیادی خطِ اساس (ڈیفالٹ)','Top'=>'اوپر','Middle'=>'درمیان','Bottom'=>'نیچے','Icon settings'=>'آئیکن کی ترتیبات','Biography icon'=>'سوانحی آئیکن','Events icon'=>'تقریبات آئیکن','Icon size'=>'آئیکن کا سائز','Icon vertical align'=>'آئیکن کی عمودی سیدھ','Icon-only links have no text baseline of their own — use this if they sit too high or low next to the artist name once Icon size is changed from the default.'=>'صرف آئیکن والے روابط کی اپنی کوئی متن بنیاد نہیں ہوتی — اگر آئیکن کا سائز ڈیفالٹ سے بدلنے کے بعد وہ فنکار کے نام کے ساتھ بہت اوپر یا نیچے نظر آئے تو اسے استعمال کریں۔','Icon color'=>'آئیکن کا رنگ','Leave unset to match the block’s own text color.'=>'بلاک کے اپنے متن کے رنگ سے ملانے کے لیے غیر متعین چھوڑ دیں۔','Artist Name'=>'فنکار کا نام','Envelope'=>'لفافہ','Speech bubble'=>'گفتگو کا بلبلہ','Contact'=>'رابطہ','Link settings'=>'رابطے کی ترتیبات','Link type'=>'رابطے کی قسم','Icon'=>'آئیکن','Biography Icon'=>'سوانحی آئیکن','Icon-only link to the artist’s biography.'=>'فنکار کی سوانح حیات کے لیے صرف آئیکن والا رابطہ۔','Events Icon'=>'تقریبات آئیکن','Icon-only link to the artist’s events archive.'=>'فنکار کے تقاریب کے آرکائیو کے لیے صرف آئیکن والا رابطہ۔','Contact Icon'=>'رابطے کا آئیکن','Opens a popover with a form to message the artist directly. Hidden automatically if the artist has turned contact messages off.'=>'ایک پاپ اوور کھولتا ہے جس میں فنکار کو براہِ راست پیغام بھیجنے کے لیے فارم ہوتا ہے۔ اگر فنکار نے رابطہ پیغامات بند کیے ہوں تو خودکار طور پر چھپ جاتا ہے۔','Artist Contact Form'=>'فنکار کے رابطے کا فارم','Lets a visitor message the current artist subdomain’s artist. Content is rendered live on the frontend, for the artist currently being viewed.'=>'وزیٹر کو موجودہ فنکار کے سب ڈومین کے فنکار کو پیغام بھیجنے 